UPDATE words SET example_en_2 = 'He grilled the vegetables on the barbecue until they were charred.', example_ko_2 = '그는 채소가 살짝 탈 때까지 바비큐에서 구웠어요.', example_en_3 = 'She marinated the chicken before grilling it.', example_ko_3 = '그녀는 닭고기를 굽기 전에 재워 두었어요.', example_en_4 = 'Grilled salmon is one of the healthiest meals you can make.', example_ko_4 = '구운 연어는 만들 수 있는 가장 건강한 식사 중 하나예요.', example_en_5 = 'Brush the meat with oil before you grill it.', example_ko_5 = '굽기 전에 고기에 오일을 발라 주세요.' WHERE id = 'w_cooking_A2_26';

