UPDATE words SET example_en_2 = 'She makes her own seasoning blend with herbs and spices.', example_ko_2 = '그녀는 허브와 향신료를 섞어 직접 조미료를 만들어요.', example_en_3 = 'The seasoning gives this dish its distinctive taste.', example_ko_3 = '이 조미료가 이 요리만의 독특한 맛을 만들어 줘요.', example_en_4 = 'He adjusted the seasoning just before serving.', example_ko_4 = '그는 내기 직전에 간을 조절했어요.', example_en_5 = 'Good seasoning is the key to a delicious meal.', example_ko_5 = '좋은 양념이 맛있는 식사의 핵심이에요.' WHERE id = 'w_cooking_B1_01';

UPDATE words SET example_en_2 = 'She left the chicken in the marinade overnight for more flavour.', example_ko_2 = '그녀는 더 깊은 맛을 위해 닭고기를 하룻밤 동안 마리네이드에 재워 두었어요.', example_en_3 = 'The marinade is made with soy sauce, ginger, and garlic.', example_ko_3 = '이 마리네이드는 간장, 생강, 마늘로 만들어요.', example_en_4 = 'Even a short marinade of thirty minutes improves the taste.', example_ko_4 = '30분만 재워도 맛이 훨씬 좋아져요.', example_en_5 = 'He used a citrus marinade to tenderise the pork.', example_ko_5 = '그는 돼지고기를 부드럽게 하기 위해 감귤류 마리네이드를 사용했어요.' WHERE id = 'w_cooking_B1_02';

UPDATE words SET example_en_2 = 'She let the stew simmer for two hours until it was rich and thick.', example_ko_2 = '그녀는 스튜가 진하고 걸쭉해질 때까지 두 시간 동안 끓였어요.', example_en_3 = 'Reduce the heat and let the sauce simmer gently.', example_ko_3 = '불을 줄이고 소스를 약하게 끓여 주세요.', example_en_4 = 'He added stock and left it to simmer on the back burner.', example_ko_4 = '그는 육수를 넣고 뒷쪽 버너에서 은근히 끓였어요.', example_en_5 = 'Let the soup simmer until all the vegetables are tender.', example_ko_5 = '채소가 모두 부드러워질 때까지 수프를 끓여 주세요.' WHERE id = 'w_cooking_B1_03';

UPDATE words SET example_en_2 = 'She prefers to steam vegetables to preserve their vitamins.', example_ko_2 = '그녀는 비타민을 보존하기 위해 채소를 쪄서 먹어요.', example_en_3 = 'Steam the buns for ten minutes until fluffy.', example_ko_3 = '찐빵을 10분 동안 쪄서 폭신하게 만들어 주세요.', example_en_4 = 'He steamed the fish with ginger and soy sauce.', example_ko_4 = '그는 생강과 간장을 넣어 생선을 쪄서 만들었어요.', example_en_5 = 'Steamed rice has a softer and stickier texture.', example_ko_5 = '찐 쌀은 더 부드럽고 찰진 식감이에요.' WHERE id = 'w_cooking_B1_04';

UPDATE words SET example_en_2 = 'She loves to deep-fry doughnuts on the weekend.', example_ko_2 = '그녀는 주말에 도넛을 튀기는 것을 좋아해요.', example_en_3 = 'Deep-fry the tofu until it is golden on the outside.', example_ko_3 = '두부 겉면이 황금빛이 될 때까지 튀겨 주세요.', example_en_4 = 'He uses a thermometer when deep-frying to maintain the right temperature.', example_ko_4 = '그는 튀길 때 온도를 맞추기 위해 온도계를 사용해요.', example_en_5 = 'Deep-fried food should be drained on paper towels.', example_ko_5 = '튀긴 음식은 키친타월 위에 올려 기름을 빼 주세요.' WHERE id = 'w_cooking_B1_05';

UPDATE words SET example_en_2 = 'She sautéed the mushrooms in butter with a pinch of thyme.', example_ko_2 = '그녀는 타임을 조금 넣어 버터에 버섯을 볶았어요.', example_en_3 = 'Sauté the shallots until they are translucent.', example_ko_3 = '샬롯이 투명해질 때까지 볶아 주세요.', example_en_4 = 'He sautéed the spinach quickly over high heat.', example_ko_4 = '그는 센 불에서 시금치를 빠르게 볶았어요.', example_en_5 = 'Sautéed garlic adds great depth to pasta dishes.', example_ko_5 = '볶은 마늘은 파스타 요리에 깊은 맛을 더해 줘요.' WHERE id = 'w_cooking_B1_06';

UPDATE words SET example_en_2 = 'She used a blender to blend the soup until smooth.', example_ko_2 = '그녀는 블렌더로 수프가 부드러워질 때까지 갈았어요.', example_en_3 = 'Blend the berries with yoghurt and honey for a smoothie.', example_ko_3 = '스무디를 만들기 위해 베리류를 요거트와 꿀과 함께 갈아 주세요.', example_en_4 = 'He blended the sauce until there were no lumps left.', example_ko_4 = '그는 덩어리가 없어질 때까지 소스를 갈았어요.', example_en_5 = 'Blend the avocado with lemon juice for a creamy dip.', example_ko_5 = '크리미한 딥을 만들기 위해 아보카도를 레몬즙과 함께 갈아 주세요.' WHERE id = 'w_cooking_B1_07';

UPDATE words SET example_en_2 = 'She whisked the cream until it formed soft peaks.', example_ko_2 = '그녀는 크림이 부드러운 봉우리 모양이 될 때까지 휘저었어요.', example_en_3 = 'Whisk the egg whites until they are stiff.', example_ko_3 = '달걀 흰자가 단단해질 때까지 휘저어 주세요.', example_en_4 = 'He used a whisk to mix the dressing quickly.', example_ko_4 = '그는 거품기를 사용해 드레싱을 빠르게 섞었어요.', example_en_5 = 'Whisk the eggs and milk together before pouring into the pan.', example_ko_5 = '달걀과 우유를 팬에 붓기 전에 함께 휘저어 주세요.' WHERE id = 'w_cooking_B1_08';

UPDATE words SET example_en_2 = 'She kneaded the bread dough for ten minutes by hand.', example_ko_2 = '그녀는 빵 반죽을 손으로 10분 동안 치댔어요.', example_en_3 = 'Knead the dough until it is smooth and elastic.', example_ko_3 = '반죽이 부드럽고 탄력 있어질 때까지 치대 주세요.', example_en_4 = 'He learned the proper technique to knead dough from a baker.', example_ko_4 = '그는 제빵사에게 반죽 치대는 올바른 방법을 배웠어요.', example_en_5 = 'Over-kneading can make the bread too dense.', example_ko_5 = '너무 많이 치대면 빵이 너무 빽빽해질 수 있어요.' WHERE id = 'w_cooking_B1_09';

UPDATE words SET example_en_2 = 'She measures each ingredient carefully to get consistent results.', example_ko_2 = '그녀는 일정한 결과를 얻기 위해 각 재료를 꼼꼼하게 계량해요.', example_en_3 = 'Measure the flour by levelling off the top of the cup.', example_ko_3 = '컵 윗면을 평평하게 깎아 밀가루를 계량해 주세요.', example_en_4 = 'He measured out the spices before adding them.', example_ko_4 = '그는 향신료를 넣기 전에 미리 계량해 두었어요.', example_en_5 = 'It is important to measure liquids at eye level.', example_ko_5 = '액체류는 눈높이에서 계량하는 것이 중요해요.' WHERE id = 'w_cooking_B1_10';

UPDATE words SET example_en_2 = 'She divided the dough into equal portions before shaping.', example_ko_2 = '그녀는 모양을 만들기 전에 반죽을 같은 크기의 부분으로 나눴어요.', example_en_3 = 'Each portion of the meal is carefully calculated for nutrition.', example_ko_3 = '각 식사 부분은 영양을 위해 꼼꼼하게 계산되어 있어요.', example_en_4 = 'He served a generous portion of pasta to each guest.', example_ko_4 = '그는 손님 각자에게 파스타를 넉넉히 담아 주었어요.', example_en_5 = 'Smaller portions can help with managing your calorie intake.', example_ko_5 = '양을 줄이면 칼로리 섭취를 관리하는 데 도움이 돼요.' WHERE id = 'w_cooking_B1_11';

UPDATE words SET example_en_2 = 'She turned the leftover roast chicken into a sandwich filling.', example_ko_2 = '그녀는 남은 로스트 치킨을 샌드위치 속 재료로 활용했어요.', example_en_3 = 'He stores leftovers in airtight containers.', example_ko_3 = '그는 남은 음식을 밀폐 용기에 보관해요.', example_en_4 = 'Leftovers from last night will make a great lunch tomorrow.', example_ko_4 = '어젯밤 남은 음식이 내일 점심으로 훌륭할 거예요.', example_en_5 = 'Never leave leftovers out of the fridge for more than two hours.', example_ko_5 = '남은 음식을 냉장고 밖에 두 시간 이상 방치하지 마세요.' WHERE id = 'w_cooking_B1_12';

UPDATE words SET example_en_2 = 'Refrigerate the dough for at least one hour before rolling it out.', example_ko_2 = '반죽을 펴기 전에 최소 한 시간 동안 냉장 보관해 주세요.', example_en_3 = 'She refrigerates the marinating meat overnight.', example_ko_3 = '그녀는 양념한 고기를 하룻밤 냉장 보관해요.', example_en_4 = 'Always refrigerate dairy products after opening.', example_ko_4 = '유제품은 개봉 후 항상 냉장 보관해 주세요.', example_en_5 = 'Refrigerate the cake for an hour so the frosting sets.', example_ko_5 = '아이싱이 굳도록 케이크를 한 시간 동안 냉장 보관해 주세요.' WHERE id = 'w_cooking_B1_13';

UPDATE words SET example_en_2 = 'She freezes summer berries to use them in the winter.', example_ko_2 = '그녀는 여름 베리류를 겨울에 사용하기 위해 얼려 두어요.', example_en_3 = 'Freeze the soup in individual portions for easy reheating.', example_ko_3 = '수프를 쉽게 데울 수 있도록 한 인분씩 얼려 두세요.', example_en_4 = 'He freezes homemade bread to keep it fresh longer.', example_ko_4 = '그는 직접 만든 빵을 더 오래 신선하게 유지하기 위해 얼려요.', example_en_5 = 'Most soups and stews freeze very well for up to three months.', example_ko_5 = '대부분의 수프와 스튜는 최대 3개월까지 잘 얼려 보관할 수 있어요.' WHERE id = 'w_cooking_B1_14';

UPDATE words SET example_en_2 = 'She thaws frozen meat in the fridge, not on the countertop.', example_ko_2 = '그녀는 냉동 고기를 조리대 위가 아닌 냉장고에서 해동해요.', example_en_3 = 'Thaw the dough overnight in the refrigerator.', example_ko_3 = '반죽은 냉장고에서 하룻밤 동안 해동해 주세요.', example_en_4 = 'It is safest to thaw fish in cold water.', example_ko_4 = '생선은 차가운 물에 해동하는 것이 가장 안전해요.', example_en_5 = 'Never thaw and refreeze meat as it can be unsafe.', example_ko_5 = '고기를 해동 후 다시 얼리는 것은 위험할 수 있으니 피해 주세요.' WHERE id = 'w_cooking_B1_15';

UPDATE words SET example_en_2 = 'She makes a grocery list every Sunday before going shopping.', example_ko_2 = '그녀는 장을 보러 가기 전에 매주 일요일 장보기 목록을 만들어요.', example_en_3 = 'He picked up groceries on the way home from work.', example_ko_3 = '그는 퇴근길에 장을 봤어요.', example_en_4 = 'Fresh grocery shopping twice a week keeps the kitchen well stocked.', example_ko_4 = '일주일에 두 번 신선 식품을 사면 주방을 잘 채울 수 있어요.', example_en_5 = 'Online grocery shopping saves a lot of time.', example_ko_5 = '온라인 장보기는 시간을 많이 절약해 줘요.' WHERE id = 'w_cooking_B1_16';

UPDATE words SET example_en_2 = 'A well-stocked pantry means you can always cook something.', example_ko_2 = '식료품 저장실을 잘 채워 두면 언제든 무언가를 요리할 수 있어요.', example_en_3 = 'She organises her pantry with labels on every shelf.', example_ko_3 = '그녀는 모든 선반에 라벨을 붙여 식료품 저장실을 정리해요.', example_en_4 = 'He checked the pantry before writing his shopping list.', example_ko_4 = '그는 장보기 목록을 작성하기 전에 식료품 저장실을 확인했어요.', example_en_5 = 'Keep canned goods and dried pasta in the pantry.', example_ko_5 = '통조림과 건조 파스타는 식료품 저장실에 보관하세요.' WHERE id = 'w_cooking_B1_17';

UPDATE words SET example_en_2 = 'Fresh herbs like basil and parsley add brightness to pasta.', example_ko_2 = '바질과 파슬리 같은 신선한 허브는 파스타에 생기를 더해 줘요.', example_en_3 = 'She grows herbs on her kitchen windowsill year-round.', example_ko_3 = '그녀는 주방 창가에 일 년 내내 허브를 키워요.', example_en_4 = 'Dried herbs are more concentrated than fresh herbs.', example_ko_4 = '건조 허브는 신선한 허브보다 향이 더 진해요.', example_en_5 = 'Add herbs at the end of cooking to preserve their aroma.', example_ko_5 = '향을 살리려면 요리가 끝날 때 허브를 넣어 주세요.' WHERE id = 'w_cooking_B1_18';

UPDATE words SET example_en_2 = 'She keeps a collection of spices in small labelled jars.', example_ko_2 = '그녀는 라벨이 붙은 작은 병에 각종 향신료를 모아 두어요.', example_en_3 = 'Ground spices lose their potency after about a year.', example_ko_3 = '갈아 놓은 향신료는 약 1년이 지나면 향이 약해져요.', example_en_4 = 'He toasted the spices in a dry pan to bring out their aroma.', example_ko_4 = '그는 향을 살리기 위해 기름 없이 팬에서 향신료를 볶았어요.', example_en_5 = 'A good spice blend is the secret to a great curry.', example_ko_5 = '훌륭한 향신료 조합이 맛있는 카레의 비결이에요.' WHERE id = 'w_cooking_B1_19';

UPDATE words SET example_en_2 = 'She adds a splash of vinegar to brighten up dull sauces.', example_ko_2 = '그녀는 밋밋한 소스를 살리기 위해 식초를 조금 넣어요.', example_en_3 = 'He uses apple cider vinegar in his salad dressings.', example_ko_3 = '그는 샐러드 드레싱에 사과 사이다 식초를 사용해요.', example_en_4 = 'Rice vinegar has a milder flavour than white wine vinegar.', example_ko_4 = '쌀 식초는 화이트 와인 식초보다 맛이 더 순해요.', example_en_5 = 'A dash of vinegar can lift the flavour of a soup.', example_ko_5 = '식초를 조금 넣으면 수프 맛이 살아나요.' WHERE id = 'w_cooking_B1_20';

UPDATE words SET example_en_2 = 'She squeezes fresh lemon over the grilled fish before serving.', example_ko_2 = '그녀는 구운 생선을 내기 전에 신선한 레몬을 짜서 뿌려요.', example_en_3 = 'He adds lemon zest to add brightness to the dessert.', example_ko_3 = '그는 디저트에 생기를 더하기 위해 레몬 제스트를 넣어요.', example_en_4 = 'Lemon juice prevents cut fruits from browning.', example_ko_4 = '레몬즙을 뿌리면 자른 과일이 갈변하는 것을 막아 줘요.', example_en_5 = 'A slice of lemon on the side makes any seafood dish better.', example_ko_5 = '레몬 한 조각을 곁들이면 어떤 해산물 요리든 더 맛있어요.' WHERE id = 'w_cooking_B1_21';

UPDATE words SET example_en_2 = 'She uses lime juice and zest in her guacamole.', example_ko_2 = '그녀는 과카몰레에 라임즙과 제스트를 사용해요.', example_en_3 = 'He squeezes lime over the tacos for a citrusy kick.', example_ko_3 = '그는 타코에 상큼한 향을 더하기 위해 라임을 짜서 뿌려요.', example_en_4 = 'Lime adds a refreshing flavour to cold drinks and desserts.', example_ko_4 = '라임은 차가운 음료와 디저트에 상쾌한 풍미를 더해 줘요.', example_en_5 = 'Lime leaves are a common ingredient in Thai cooking.', example_ko_5 = '라임 잎은 태국 요리에서 흔히 사용되는 재료예요.' WHERE id = 'w_cooking_B1_22';

UPDATE words SET example_en_2 = 'She made a rich broth from chicken bones and vegetables.', example_ko_2 = '그녀는 닭 뼈와 채소로 진한 육수를 만들었어요.', example_en_3 = 'He uses homemade broth instead of store-bought for better flavour.', example_ko_3 = '그는 더 좋은 맛을 위해 사온 육수 대신 직접 만든 육수를 써요.', example_en_4 = 'She simmered the broth for four hours to develop a deep flavour.', example_ko_4 = '그녀는 깊은 맛을 내기 위해 육수를 4시간 동안 끓였어요.', example_en_5 = 'Add the noodles directly into the simmering broth.', example_ko_5 = '국수를 끓고 있는 육수에 바로 넣어 주세요.' WHERE id = 'w_cooking_B1_23';

UPDATE words SET example_en_2 = 'She uses beef stock as the base for her French onion soup.', example_ko_2 = '그녀는 프렌치 어니언 수프의 베이스로 소고기 육수를 사용해요.', example_en_3 = 'He reduced the stock to make a rich, concentrated sauce.', example_ko_3 = '그는 진하고 농축된 소스를 만들기 위해 육수를 졸였어요.', example_en_4 = 'Vegetable stock is a great option for vegetarian dishes.', example_ko_4 = '채소 육수는 채식 요리에 훌륭한 선택이에요.', example_en_5 = 'Store homemade stock in the freezer in ice cube trays.', example_ko_5 = '직접 만든 육수는 얼음 틀에 넣어 냉동 보관해 주세요.' WHERE id = 'w_cooking_B1_24';

UPDATE words SET example_en_2 = 'She made a hearty stew with potatoes, carrots, and beef.', example_ko_2 = '그녀는 감자, 당근, 소고기로 든든한 스튜를 만들었어요.', example_en_3 = 'The stew tastes even better the next day.', example_ko_3 = '스튜는 다음 날 더 맛있어요.', example_en_4 = 'He thickened the stew with a spoonful of cornstarch.', example_ko_4 = '그는 스튜에 녹말가루 한 숟가락을 넣어 걸쭉하게 만들었어요.', example_en_5 = 'A good stew should have tender meat and rich gravy.', example_ko_5 = '좋은 스튜에는 부드러운 고기와 진한 그레이비가 있어야 해요.' WHERE id = 'w_cooking_B1_25';

UPDATE words SET example_en_2 = 'She made a chicken and vegetable casserole for the whole family.', example_ko_2 = '그녀는 온 가족을 위해 닭고기와 채소 캐서롤을 만들었어요.', example_en_3 = 'He left the casserole in the oven for an hour.', example_ko_3 = '그는 캐서롤을 오븐에서 한 시간 동안 두었어요.', example_en_4 = 'Casserole dishes are perfect for feeding a large group.', example_ko_4 = '캐서롤은 많은 사람을 위해 요리할 때 완벽해요.', example_en_5 = 'She covered the casserole dish with foil to keep the moisture in.', example_ko_5 = '그녀는 수분을 유지하기 위해 캐서롤 용기를 호일로 덮었어요.' WHERE id = 'w_cooking_B1_26';

UPDATE words SET example_en_2 = 'She made a light tempura batter with ice-cold water.', example_ko_2 = '그녀는 얼음처럼 차가운 물로 가벼운 튀김 반죽을 만들었어요.', example_en_3 = 'The fish and chips batter should be thin and crispy.', example_ko_3 = '피시 앤드 칩스 반죽은 얇고 바삭해야 해요.', example_en_4 = 'He dipped the onion rings in batter before frying.', example_ko_4 = '그는 튀기기 전에 양파 링을 반죽에 담갔어요.', example_en_5 = 'Let the batter rest in the fridge for thirty minutes before using.', example_ko_5 = '반죽은 사용하기 전에 냉장고에서 30분 동안 쉬게 해 주세요.' WHERE id = 'w_cooking_B1_27';

UPDATE words SET example_en_2 = 'She rolled the dough flat on a floured surface.', example_ko_2 = '그녀는 밀가루를 뿌린 표면에서 반죽을 평평하게 밀었어요.', example_en_3 = 'The dough should be soft and smooth after kneading.', example_ko_3 = '반죽은 치댄 후에 부드럽고 매끄러워야 해요.', example_en_4 = 'He shaped the dough into small rolls before baking.', example_ko_4 = '그는 굽기 전에 반죽을 작은 롤 모양으로 빚었어요.', example_en_5 = 'Cover the dough with a damp cloth while it rests.', example_ko_5 = '반죽을 쉬는 동안 젖은 천으로 덮어 주세요.' WHERE id = 'w_cooking_B1_28';

UPDATE words SET example_en_2 = 'She added a packet of yeast to the warm water before mixing.', example_ko_2 = '그녀는 섞기 전에 따뜻한 물에 이스트 한 봉지를 넣었어요.', example_en_3 = 'Active dry yeast needs to be activated in warm water first.', example_ko_3 = '활성 건조 이스트는 먼저 따뜻한 물에서 활성화해야 해요.', example_en_4 = 'Yeast is the ingredient that makes bread rise and become fluffy.', example_ko_4 = '이스트는 빵을 부풀어 오르고 폭신하게 만드는 재료예요.', example_en_5 = 'Too much yeast can cause the bread to rise too quickly.', example_ko_5 = '이스트를 너무 많이 넣으면 빵이 너무 빨리 부풀 수 있어요.' WHERE id = 'w_cooking_B1_29';

UPDATE words SET example_en_2 = 'She covered the bowl and let the dough rise for one hour.', example_ko_2 = '그녀는 그릇을 덮고 반죽이 한 시간 동안 부풀도록 두었어요.', example_en_3 = 'The bread did not rise well because the yeast was old.', example_ko_3 = '이스트가 오래되어 빵이 잘 부풀지 않았어요.', example_en_4 = 'Let the dough rise in a warm spot in the kitchen.', example_ko_4 = '주방의 따뜻한 곳에서 반죽이 부풀도록 두세요.', example_en_5 = 'The dough doubled in size after an hour of rising.', example_ko_5 = '반죽이 한 시간 부풀고 나서 두 배 크기가 됐어요.' WHERE id = 'w_cooking_B1_30';

UPDATE words SET example_en_2 = 'She always preheats the oven before putting the cake in.', example_ko_2 = '그녀는 항상 케이크를 넣기 전에 오븐을 예열해요.', example_en_3 = 'Preheat the oven to 200°C while you prepare the dough.', example_ko_3 = '반죽을 준비하는 동안 오븐을 200°C로 예열해 주세요.', example_en_4 = 'He always checks that the oven is fully preheated before baking.', example_ko_4 = '그는 굽기 전에 항상 오븐이 완전히 예열됐는지 확인해요.', example_en_5 = 'Skipping the preheat step can lead to uneven baking.', example_ko_5 = '예열 단계를 건너뛰면 고르게 굽기가 어려울 수 있어요.' WHERE id = 'w_cooking_B1_31';

UPDATE words SET example_en_2 = 'The oven timer beeped when the roast was ready.', example_ko_2 = '로스트가 다 됐을 때 오븐 타이머가 울렸어요.', example_en_3 = 'She cleans the oven every month to keep it working well.', example_ko_3 = '그녀는 오븐이 잘 작동하도록 매달 청소해요.', example_en_4 = 'He placed the tray on the middle rack of the oven.', example_ko_4 = '그는 트레이를 오븐의 중간 선반에 넣었어요.', example_en_5 = 'The oven needs about fifteen minutes to reach full temperature.', example_ko_5 = '오븐이 최고 온도에 도달하는 데 약 15분이 걸려요.' WHERE id = 'w_cooking_B1_32';

UPDATE words SET example_en_2 = 'The internal temperature of the chicken should reach 75°C.', example_ko_2 = '닭고기의 내부 온도는 75°C에 도달해야 해요.', example_en_3 = 'She uses a thermometer to check the temperature of the oil.', example_ko_3 = '그녀는 온도계를 사용해 기름 온도를 확인해요.', example_en_4 = 'Keep the milk at a low temperature when making yoghurt.', example_ko_4 = '요거트를 만들 때는 우유를 낮은 온도로 유지해 주세요.', example_en_5 = 'The correct oven temperature makes all the difference when baking.', example_ko_5 = '베이킹에서 올바른 오븐 온도는 매우 중요해요.' WHERE id = 'w_cooking_B1_33';

UPDATE words SET example_en_2 = 'Always check the shelf life before buying packaged food.', example_ko_2 = '포장 식품을 구입하기 전에 항상 유통 기한을 확인하세요.', example_en_3 = 'Freezing extends the shelf life of most foods.', example_ko_3 = '냉동하면 대부분의 식품 유통 기한이 늘어나요.', example_en_4 = 'The shelf life of fresh bread is only two to three days.', example_ko_4 = '신선한 빵의 유통 기한은 이틀에서 사흘밖에 되지 않아요.', example_en_5 = 'Proper storage can significantly extend the shelf life of herbs.', example_ko_5 = '적절한 보관 방법으로 허브의 유통 기한을 크게 늘릴 수 있어요.' WHERE id = 'w_cooking_B1_34';

UPDATE words SET example_en_2 = 'Check the expiry date before using dairy products.', example_ko_2 = '유제품을 사용하기 전에 유통 기한을 확인해 주세요.', example_en_3 = 'She threw away the yoghurt because it was past its expiry date.', example_ko_3 = '그녀는 요거트의 유통 기한이 지나서 버렸어요.', example_en_4 = 'He always buys products with the latest expiry date.', example_ko_4 = '그는 항상 유통 기한이 가장 늦은 제품을 사요.', example_en_5 = 'The expiry date on canned goods is usually several years away.', example_ko_5 = '통조림 식품의 유통 기한은 보통 몇 년 뒤예요.' WHERE id = 'w_cooking_B1_35';

