UPDATE words SET example_en_2 = 'The restaurant is known for its French cuisine and elegant atmosphere.', example_ko_2 = '그 식당은 프랑스 요리와 우아한 분위기로 유명해요.', example_en_3 = 'She studied Italian cuisine for two years in Rome.', example_ko_3 = '그녀는 로마에서 2년 동안 이탈리아 요리를 공부했어요.', example_en_4 = 'Thai cuisine balances sweet, sour, salty, and spicy flavours.', example_ko_4 = '태국 요리는 달콤하고, 새콤하고, 짭짤하고, 매운 맛의 균형이 잘 맞아요.', example_en_5 = 'Exploring local cuisine is one of the best parts of travelling.', example_ko_5 = '현지 요리를 탐색하는 것은 여행의 가장 좋은 부분 중 하나예요.' WHERE id = 'w_cooking_B2_01';

UPDATE words SET example_en_2 = 'She enrolled in a culinary school to improve her cooking skills.', example_ko_2 = '그녀는 요리 실력을 향상시키기 위해 요리 학교에 등록했어요.', example_en_3 = 'He has a culinary background from working in top restaurants.', example_ko_3 = '그는 최고의 식당에서 일한 요리 경력이 있어요.', example_en_4 = 'Culinary creativity allows chefs to express themselves through food.', example_ko_4 = '요리적 창의성은 셰프들이 음식을 통해 자신을 표현할 수 있게 해줘요.', example_en_5 = 'The culinary arts combine science, technique, and creativity.', example_ko_5 = '요리 예술은 과학, 기술, 그리고 창의성을 결합해요.' WHERE id = 'w_cooking_B2_02';

UPDATE words SET example_en_2 = 'Mastering the technique of making a perfect roux takes practice.', example_ko_2 = '완벽한 루를 만드는 기술을 익히는 데는 연습이 필요해요.', example_en_3 = 'The chef demonstrated the knife technique step by step.', example_ko_3 = '셰프가 칼 기술을 단계별로 시연했어요.', example_en_4 = 'Proper baking technique ensures consistent results every time.', example_ko_4 = '올바른 베이킹 기술은 매번 일관된 결과를 보장해요.', example_en_5 = 'She refined her technique by practising every day.', example_ko_5 = '그녀는 매일 연습함으로써 기술을 다듬었어요.' WHERE id = 'w_cooking_B2_03';

UPDATE words SET example_en_2 = 'The chef gave great attention to the presentation of each plate.', example_ko_2 = '셰프는 각 접시의 프레젠테이션에 많은 신경을 썼어요.', example_en_3 = 'Food presentation can make a dish look more appealing.', example_ko_3 = '음식 프레젠테이션은 요리를 더 매력적으로 보이게 할 수 있어요.', example_en_4 = 'She practised food presentation by watching videos online.', example_ko_4 = '그녀는 온라인 영상을 보면서 음식 프레젠테이션을 연습했어요.', example_en_5 = 'Good presentation can elevate even a simple dish.', example_ko_5 = '좋은 프레젠테이션은 간단한 요리도 격상시킬 수 있어요.' WHERE id = 'w_cooking_B2_04';

UPDATE words SET example_en_2 = 'He learned plating techniques to make his dishes look professional.', example_ko_2 = '그는 요리를 전문적으로 보이게 하기 위한 플레이팅 기술을 배웠어요.', example_en_3 = 'She uses tweezers for precise plating in her restaurant.', example_ko_3 = '그녀는 식당에서 정밀한 플레이팅을 위해 핀셋을 사용해요.', example_en_4 = 'Plating is as important as cooking in fine dining.', example_ko_4 = '파인 다이닝에서 플레이팅은 요리만큼 중요해요.', example_en_5 = 'Creative plating turns a meal into a visual experience.', example_ko_5 = '창의적인 플레이팅은 식사를 시각적인 경험으로 만들어요.' WHERE id = 'w_cooking_B2_05';

UPDATE words SET example_en_2 = 'A sprig of fresh mint makes a beautiful garnish for desserts.', example_ko_2 = '신선한 민트 한 줄기는 디저트에 아름다운 가니쉬가 돼요.', example_en_3 = 'He used a lemon twist as a garnish for the cocktail.', example_ko_3 = '그는 칵테일에 레몬 트위스트를 가니쉬로 사용했어요.', example_en_4 = 'A garnish should complement the flavour of the dish.', example_ko_4 = '가니쉬는 요리의 맛을 보완해야 해요.', example_en_5 = 'She garnished the soup with a drizzle of cream and fresh herbs.', example_ko_5 = '그녀는 수프에 크림과 신선한 허브를 뿌려 가니쉬했어요.' WHERE id = 'w_cooking_B2_06';

UPDATE words SET example_en_2 = 'She made a balsamic reduction to drizzle over the salad.', example_ko_2 = '그녀는 샐러드 위에 뿌릴 발사믹 리덕션을 만들었어요.', example_en_3 = 'The sauce became richer after a long reduction process.', example_ko_3 = '소스는 오랜 리덕션 과정 후에 더욱 진해졌어요.', example_en_4 = 'A red wine reduction pairs well with grilled steak.', example_ko_4 = '레드 와인 리덕션은 구운 스테이크와 잘 어울려요.', example_en_5 = 'Reduction intensifies the flavour of a sauce by removing water.', example_ko_5 = '리덕션은 수분을 제거함으로써 소스의 맛을 진하게 해요.' WHERE id = 'w_cooking_B2_07';

UPDATE words SET example_en_2 = 'She caramelized the onions slowly over low heat for forty minutes.', example_ko_2 = '그녀는 양파를 약불에서 40분 동안 천천히 캐러멜화했어요.', example_en_3 = 'He caramelized the sugar until it turned a deep amber colour.', example_ko_3 = '그는 설탕이 짙은 호박색이 될 때까지 캐러멜화했어요.', example_en_4 = 'Caramelized onions add a sweet depth of flavour to burgers.', example_ko_4 = '캐러멜화한 양파는 버거에 달콤한 풍미의 깊이를 더해요.', example_en_5 = 'You need patience to caramelize onions properly.', example_ko_5 = '양파를 제대로 캐러멜화하려면 인내가 필요해요.' WHERE id = 'w_cooking_B2_08';

UPDATE words SET example_en_2 = 'She deglazed the pan with white wine to make the sauce.', example_ko_2 = '그녀는 소스를 만들기 위해 화이트 와인으로 팬을 디글레이즈했어요.', example_en_3 = 'He deglazed the roasting tin with beef stock after browning.', example_ko_3 = '그는 고기를 볶은 후 쇠고기 육수로 로스팅 팬을 디글레이즈했어요.', example_en_4 = 'Deglazing lifts the browned bits from the bottom of the pan.', example_ko_4 = '디글레이징은 팬 바닥에 붙은 갈색 잔류물을 걷어내요.', example_en_5 = 'Always deglaze with a liquid that complements your dish.', example_ko_5 = '항상 요리에 어울리는 액체로 디글레이징해 주세요.' WHERE id = 'w_cooking_B2_09';

UPDATE words SET example_en_2 = 'She shook the jar vigorously to emulsify the vinaigrette.', example_ko_2 = '그녀는 비네그레트를 유화시키기 위해 병을 세게 흔들었어요.', example_en_3 = 'Adding oil slowly helps to emulsify the mayonnaise properly.', example_ko_3 = '오일을 천천히 넣으면 마요네즈를 제대로 유화시키는 데 도움이 돼요.', example_en_4 = 'A food processor can help you emulsify sauces quickly.', example_ko_4 = '푸드 프로세서는 소스를 빠르게 유화시키는 데 도움이 돼요.', example_en_5 = 'Lecithin in egg yolk helps to emulsify oil and water.', example_ko_5 = '달걀 노른자의 레시틴이 오일과 물을 유화시키는 데 도움이 돼요.' WHERE id = 'w_cooking_B2_10';

UPDATE words SET example_en_2 = 'He poached the eggs in gently simmering water with a splash of vinegar.', example_ko_2 = '그는 달걀을 식초를 조금 넣은 약하게 끓는 물에서 포치했어요.', example_en_3 = 'She poached the salmon in a light vegetable broth.', example_ko_3 = '그녀는 연어를 가벼운 채소 육수에서 포치했어요.', example_en_4 = 'Poached chicken is low in fat and easy to digest.', example_ko_4 = '포치한 닭고기는 지방이 적고 소화하기 쉬워요.', example_en_5 = 'Poaching keeps delicate proteins moist and tender.', example_ko_5 = '포칭은 섬세한 단백질을 촉촉하고 부드럽게 유지해요.' WHERE id = 'w_cooking_B2_11';

UPDATE words SET example_en_2 = 'She blanched the green beans for two minutes to keep their colour.', example_ko_2 = '그녀는 색을 유지하기 위해 녹두를 2분간 데쳤어요.', example_en_3 = 'He blanched the tomatoes so the skins would peel off easily.', example_ko_3 = '그는 껍질이 쉽게 벗겨지도록 토마토를 데쳤어요.', example_en_4 = 'Blanching removes the bitterness from some vegetables.', example_ko_4 = '데치기는 일부 채소의 쓴맛을 없애요.', example_en_5 = 'Always transfer blanched vegetables to ice water immediately.', example_ko_5 = '데친 채소는 즉시 얼음물로 옮겨 주세요.' WHERE id = 'w_cooking_B2_12';

UPDATE words SET example_en_2 = 'She braised the short ribs for three hours until they were tender.', example_ko_2 = '그녀는 갈비가 부드러워질 때까지 3시간 동안 브레이징했어요.', example_en_3 = 'He braised the cabbage with bacon and apple cider.', example_ko_3 = '그는 베이컨과 사과 사이다로 양배추를 브레이징했어요.', example_en_4 = 'Braising tough cuts of meat makes them fork-tender.', example_ko_4 = '질긴 부위의 고기를 브레이징하면 포크로 쉽게 잘릴 정도로 부드러워져요.', example_en_5 = 'The braised lamb fell apart at the touch of a spoon.', example_ko_5 = '브레이징한 양고기는 숟가락 하나에 부드럽게 분리됐어요.' WHERE id = 'w_cooking_B2_13';

UPDATE words SET example_en_2 = 'The chef flambéed the crêpes suzette tableside with orange liqueur.', example_ko_2 = '셰프가 테이블 옆에서 오렌지 리큐르로 크레프 쉬제트를 플람베했어요.', example_en_3 = 'He flambéed the bananas with rum for the dessert.', example_ko_3 = '그는 디저트를 위해 럼으로 바나나를 플람베했어요.', example_en_4 = 'Flambéing burns off the alcohol while adding a caramelized flavour.', example_ko_4 = '플람베는 알코올을 태우면서 캐러멜화된 풍미를 더해요.', example_en_5 = 'Always be careful when flambéing dishes near curtains or flammable materials.', example_ko_5 = '커튼이나 가연성 물질 근처에서 플람베할 때는 항상 조심해 주세요.' WHERE id = 'w_cooking_B2_14';

UPDATE words SET example_en_2 = 'She decided to ferment the cabbage to make homemade kimchi.', example_ko_2 = '그녀는 직접 담근 김치를 만들기 위해 배추를 발효시키기로 했어요.', example_en_3 = 'The yoghurt is left to ferment at room temperature overnight.', example_ko_3 = '요거트는 하룻밤 동안 실온에서 발효되도록 둬요.', example_en_4 = 'He learned how to ferment hot sauce from a YouTube tutorial.', example_ko_4 = '그는 유튜브 튜토리얼을 통해 핫소스를 발효하는 방법을 배웠어요.', example_en_5 = 'Fermented foods are rich in probiotics that support gut health.', example_ko_5 = '발효 식품은 장 건강을 지원하는 프로바이오틱스가 풍부해요.' WHERE id = 'w_cooking_B2_15';

UPDATE words SET example_en_2 = 'She preserves seasonal fruits as jam every summer.', example_ko_2 = '그녀는 매년 여름에 제철 과일을 잼으로 보존해요.', example_en_3 = 'Salt has been used to preserve food for thousands of years.', example_ko_3 = '소금은 수천 년 동안 식품 보존에 사용되어 왔어요.', example_en_4 = 'He preserves herbs in olive oil to use them through winter.', example_ko_4 = '그는 겨울 내내 사용하기 위해 허브를 올리브 오일에 보존해요.', example_en_5 = 'Traditional methods to preserve food include drying, salting, and smoking.', example_ko_5 = '식품 보존의 전통적인 방법으로는 건조, 소금 절임, 훈제가 있어요.' WHERE id = 'w_cooking_B2_16';

UPDATE words SET example_en_2 = 'She pickled cucumbers with garlic and dill for the winter.', example_ko_2 = '그녀는 겨울을 위해 오이를 마늘과 딜로 피클로 담갔어요.', example_en_3 = 'He pickled red onions to serve alongside tacos.', example_ko_3 = '그는 타코와 함께 낼 레드 어니언을 피클로 만들었어요.', example_en_4 = 'Pickled vegetables add a tangy contrast to rich dishes.', example_ko_4 = '피클된 채소는 진한 음식에 새콤한 대비를 더해요.', example_en_5 = 'Quick pickling only takes about thirty minutes.', example_ko_5 = '빠른 피클링은 약 30분밖에 걸리지 않아요.' WHERE id = 'w_cooking_B2_17';

UPDATE words SET example_en_2 = 'He cured the salmon with salt and sugar for twenty-four hours.', example_ko_2 = '그는 연어를 소금과 설탕으로 24시간 동안 큐어했어요.', example_en_3 = 'Cured meats like prosciutto are enjoyed around the world.', example_ko_3 = '프로슈토와 같은 큐어드 미트는 전 세계에서 즐겨 먹어요.', example_en_4 = 'She learned to cure her own bacon at home.', example_ko_4 = '그녀는 집에서 직접 베이컨을 큐어하는 법을 배웠어요.', example_en_5 = 'Curing removes moisture to prevent bacterial growth in meat.', example_ko_5 = '큐어링은 고기의 세균 증식을 막기 위해 수분을 제거해요.' WHERE id = 'w_cooking_B2_18';

UPDATE words SET example_en_2 = 'He smoked the brisket over hickory wood for twelve hours.', example_ko_2 = '그는 히코리 나무 위에서 브리스킷을 12시간 동안 훈제했어요.', example_en_3 = 'She smoked the trout in her backyard using an old oil drum.', example_ko_3 = '그녀는 낡은 기름통을 이용해 뒷마당에서 송어를 훈제했어요.', example_en_4 = 'Smoked paprika adds a deep, earthy flavour to stews.', example_ko_4 = '훈제 파프리카는 스튜에 깊고 흙내 나는 풍미를 더해요.', example_en_5 = 'Cold smoking preserves food without cooking it.', example_ko_5 = '냉훈법은 음식을 익히지 않고 보존해요.' WHERE id = 'w_cooking_B2_19';

UPDATE words SET example_en_2 = 'She infused the cream with vanilla beans overnight.', example_ko_2 = '그녀는 바닐라 빈을 하룻밤 동안 크림에 우려냈어요.', example_en_3 = 'He infused olive oil with rosemary and garlic.', example_ko_3 = '그는 올리브 오일에 로즈마리와 마늘을 우려냈어요.', example_en_4 = 'You can infuse tea with dried flowers for a floral flavour.', example_ko_4 = '말린 꽃을 우려내 꽃향기 나는 차를 만들 수 있어요.', example_en_5 = 'The chef infused the broth with lemongrass and ginger.', example_ko_5 = '셰프는 레몬그라스와 생강을 육수에 우려냈어요.' WHERE id = 'w_cooking_B2_20';

UPDATE words SET example_en_2 = 'The dish had a pleasant crispy texture from the breadcrumbs on top.', example_ko_2 = '그 요리는 위에 얹은 빵가루 덕분에 기분 좋은 바삭한 질감이 있었어요.', example_en_3 = 'She chose ingredients with contrasting textures to make the dish interesting.', example_ko_3 = '그녀는 요리를 흥미롭게 만들기 위해 대비되는 질감의 재료를 선택했어요.', example_en_4 = 'Texture plays an important role in how we enjoy food.', example_ko_4 = '질감은 음식을 즐기는 방식에서 중요한 역할을 해요.', example_en_5 = 'The smooth texture of the mousse contrasted well with the crunchy base.', example_ko_5 = '무스의 부드러운 질감은 바삭한 베이스와 잘 대비됐어요.' WHERE id = 'w_cooking_B2_21';

UPDATE words SET example_en_2 = 'The aroma of freshly baked bread filled the whole house.', example_ko_2 = '갓 구운 빵의 향기가 집 안 전체에 퍼졌어요.', example_en_3 = 'The aroma of garlic and butter is impossible to resist.', example_ko_3 = '마늘과 버터의 향기는 저항하기 어려워요.', example_en_4 = 'A good coffee has a rich and inviting aroma.', example_ko_4 = '좋은 커피는 풍부하고 기분 좋은 향기를 가지고 있어요.', example_en_5 = 'She could identify the herb by its distinctive aroma.', example_ko_5 = '그녀는 독특한 향기로 그 허브를 알아볼 수 있었어요.' WHERE id = 'w_cooking_B2_22';

UPDATE words SET example_en_2 = 'Soy sauce and mushrooms are both rich sources of umami.', example_ko_2 = '간장과 버섯은 모두 우마미의 풍부한 원천이에요.', example_en_3 = 'Adding a little fish sauce increases the umami in the dish.', example_ko_3 = '피시 소스를 조금 넣으면 요리의 우마미가 높아져요.', example_en_4 = 'Umami is often described as a rich, savoury, and satisfying taste.', example_ko_4 = '우마미는 흔히 풍부하고, 감칠맛 나며, 만족스러운 맛으로 묘사돼요.', example_en_5 = 'Parmesan cheese is a natural source of umami flavour.', example_ko_5 = '파마산 치즈는 우마미 풍미의 자연적인 원천이에요.' WHERE id = 'w_cooking_B2_23';

UPDATE words SET example_en_2 = 'A savory broth is the base of many traditional soups.', example_ko_2 = '감칠맛 나는 육수는 많은 전통 수프의 기본이에요.', example_en_3 = 'She prefers savory breakfasts over sweet ones.', example_ko_3 = '그녀는 달콤한 아침 식사보다 짭조름한 아침 식사를 더 좋아해요.', example_en_4 = 'Herbs like thyme and rosemary add a savory depth to roasted meats.', example_ko_4 = '타임과 로즈마리 같은 허브는 구운 고기에 감칠맛 나는 깊이를 더해요.', example_en_5 = 'The savory filling inside the pastry was perfectly seasoned.', example_ko_5 = '페이스트리 안의 감칠맛 나는 속재료가 간이 딱 맞았어요.' WHERE id = 'w_cooking_B2_24';

UPDATE words SET example_en_2 = 'The bitter taste of dark chocolate pairs well with sweet cream.', example_ko_2 = '다크 초콜릿의 쓴맛은 달콤한 크림과 잘 어울려요.', example_en_3 = 'Radicchio has a pleasantly bitter flavour that balances rich dishes.', example_ko_3 = '라디키오는 진한 요리의 균형을 잡아주는 적절히 쓴맛이 있어요.', example_en_4 = 'A squeeze of lemon can offset the bitterness of some greens.', example_ko_4 = '레몬즙을 조금 짜면 일부 채소의 쓴맛을 잡을 수 있어요.', example_en_5 = 'She learned to appreciate the bitter notes in her morning espresso.', example_ko_5 = '그녀는 아침 에스프레소의 쓴 맛을 즐길 수 있게 됐어요.' WHERE id = 'w_cooking_B2_25';

UPDATE words SET example_en_2 = 'A touch of vinegar adds acidity and brightness to the sauce.', example_ko_2 = '식초를 조금 넣으면 소스에 산도와 상쾌함이 더해져요.', example_en_3 = 'The acidity of lime juice balances the richness of avocado.', example_ko_3 = '라임즙의 산도는 아보카도의 풍부함을 균형 있게 해줘요.', example_en_4 = 'Too much acidity in a dish can be corrected with a pinch of sugar.', example_ko_4 = '요리의 산도가 너무 높으면 설탕을 조금 넣어 조정할 수 있어요.', example_en_5 = 'Wine adds acidity to marinades, helping to tenderise the meat.', example_ko_5 = '와인은 마리네이드에 산도를 더해 고기를 연하게 하는 데 도움이 돼요.' WHERE id = 'w_cooking_B2_26';

UPDATE words SET example_en_2 = 'Achieving balance between sweet and sour is the key to a great dressing.', example_ko_2 = '달콤함과 새콤함의 균형을 맞추는 것이 훌륭한 드레싱의 핵심이에요.', example_en_3 = 'She adjusted the seasoning until the dish had the right balance.', example_ko_3 = '그녀는 요리의 간이 딱 맞을 때까지 양념을 조정했어요.', example_en_4 = 'A balanced meal includes proteins, carbohydrates, and healthy fats.', example_ko_4 = '균형 잡힌 식사에는 단백질, 탄수화물, 건강한 지방이 포함돼요.', example_en_5 = 'The chef carefully maintained the balance of flavours throughout the menu.', example_ko_5 = '셰프는 메뉴 전반에 걸쳐 맛의 균형을 신중하게 유지했어요.' WHERE id = 'w_cooking_B2_27';

UPDATE words SET example_en_2 = 'He used the contrast between hot and cold temperatures to surprise diners.', example_ko_2 = '그는 뜨거움과 차가움의 대비를 이용해 식사객을 놀라게 했어요.', example_en_3 = 'The contrast of crunchy nuts and soft cheese made the salad interesting.', example_ko_3 = '바삭한 견과류와 부드러운 치즈의 대비가 샐러드를 흥미롭게 만들었어요.', example_en_4 = 'Salt can create a flavour contrast that enhances sweetness in desserts.', example_ko_4 = '소금은 디저트에서 단맛을 강조하는 맛의 대비를 만들 수 있어요.', example_en_5 = 'Using colour contrast in plating makes the dish visually appealing.', example_ko_5 = '플레이팅에서 색상 대비를 사용하면 요리가 시각적으로 매력적으로 보여요.' WHERE id = 'w_cooking_B2_28';

UPDATE words SET example_en_2 = 'Wine pairing can elevate the dining experience significantly.', example_ko_2 = '와인 페어링은 식사 경험을 크게 향상시킬 수 있어요.', example_en_3 = 'She recommended a cheese pairing for each item on the menu.', example_ko_3 = '그녀는 메뉴의 각 항목에 맞는 치즈 페어링을 추천했어요.', example_en_4 = 'The pairing of chocolate and chilli creates a bold and complex flavour.', example_ko_4 = '초콜릿과 칠리의 페어링은 대담하고 복잡한 맛을 만들어요.', example_en_5 = 'He studied food and wine pairing to become a sommelier.', example_ko_5 = '그는 소믈리에가 되기 위해 음식과 와인 페어링을 공부했어요.' WHERE id = 'w_cooking_B2_29';

UPDATE words SET example_en_2 = 'The menu featured a fusion of Korean and Mexican flavours.', example_ko_2 = '메뉴에는 한국과 멕시코 맛의 퓨전이 있었어요.', example_en_3 = 'Fusion cooking allows chefs to experiment freely with ingredients.', example_ko_3 = '퓨전 요리는 셰프가 재료를 자유롭게 실험할 수 있게 해줘요.', example_en_4 = 'She opened a restaurant that specialised in Asian fusion cuisine.', example_ko_4 = '그녀는 아시안 퓨전 요리를 전문으로 하는 식당을 열었어요.', example_en_5 = 'Fusion dishes can introduce people to new flavour combinations.', example_ko_5 = '퓨전 요리는 사람들에게 새로운 맛의 조합을 소개할 수 있어요.' WHERE id = 'w_cooking_B2_30';

UPDATE words SET example_en_2 = 'He buys his bread from an artisan bakery near his home.', example_ko_2 = '그는 집 근처의 장인 빵집에서 빵을 사요.', example_en_3 = 'Artisan cheese is made using traditional methods and local milk.', example_ko_3 = '장인 치즈는 전통적인 방법과 지역 우유를 사용해 만들어요.', example_en_4 = 'She values artisan products because of the care put into making them.', example_ko_4 = '그녀는 만드는 데 기울인 정성 때문에 장인 제품을 소중히 여겨요.', example_en_5 = 'Artisan producers focus on quality over mass production.', example_ko_5 = '장인 생산자들은 대량 생산보다 품질을 중시해요.' WHERE id = 'w_cooking_B2_31';

UPDATE words SET example_en_2 = 'She chose the restaurant because of its commitment to sustainable sourcing.', example_ko_2 = '그녀는 지속 가능한 조달에 대한 헌신 때문에 그 식당을 선택했어요.', example_en_3 = 'Sustainable fishing helps to protect marine ecosystems.', example_ko_3 = '지속 가능한 어업은 해양 생태계를 보호하는 데 도움이 돼요.', example_en_4 = 'Many chefs now choose sustainable ingredients to reduce their impact.', example_ko_4 = '많은 셰프들이 이제 환경 영향을 줄이기 위해 지속 가능한 재료를 선택해요.', example_en_5 = 'Sustainable packaging reduces waste in the food industry.', example_ko_5 = '지속 가능한 포장은 식품 산업의 폐기물을 줄여요.' WHERE id = 'w_cooking_B2_32';

UPDATE words SET example_en_2 = 'The restaurant advertises organic sourcing for all its vegetables.', example_ko_2 = '그 식당은 모든 채소에 대한 유기농 조달을 광고해요.', example_en_3 = 'Organic sourcing supports farmers who avoid synthetic pesticides.', example_ko_3 = '유기농 조달은 합성 농약을 사용하지 않는 농부들을 지원해요.', example_en_4 = 'She prefers organic sourcing for her meal-prep business.', example_ko_4 = '그녀는 밀프렙 사업을 위해 유기농 조달을 선호해요.', example_en_5 = 'Organic sourcing can be more expensive but the quality is often superior.', example_ko_5 = '유기농 조달은 더 비쌀 수 있지만 품질이 종종 더 우수해요.' WHERE id = 'w_cooking_B2_33';

UPDATE words SET example_en_2 = 'The farm-to-table concept connects diners directly with local producers.', example_ko_2 = '팜투테이블 개념은 식사객을 지역 생산자와 직접 연결해요.', example_en_3 = 'She opened a farm-to-table restaurant in the countryside.', example_ko_3 = '그녀는 시골에 팜투테이블 식당을 열었어요.', example_en_4 = 'Farm-to-table menus change with the seasons.', example_ko_4 = '팜투테이블 메뉴는 계절에 따라 바뀌어요.', example_en_5 = 'He supports farm-to-table restaurants because they use fresh local ingredients.', example_ko_5 = '그는 신선한 지역 재료를 사용하기 때문에 팜투테이블 식당을 지지해요.' WHERE id = 'w_cooking_B2_34';

UPDATE words SET example_en_2 = 'The chef implemented a zero waste policy in her kitchen.', example_ko_2 = '셰프는 주방에 제로 웨이스트 정책을 시행했어요.', example_en_3 = 'Zero waste cooking means finding a use for every part of the ingredient.', example_ko_3 = '제로 웨이스트 요리는 재료의 모든 부분을 활용하는 것을 의미해요.', example_en_4 = 'She makes vegetable stock from scraps as part of her zero waste approach.', example_ko_4 = '그녀는 제로 웨이스트 방식의 일환으로 채소 부스러기로 육수를 만들어요.', example_en_5 = 'Zero waste practices can significantly reduce a restaurant''s environmental impact.', example_ko_5 = '제로 웨이스트 관행은 식당의 환경 영향을 크게 줄일 수 있어요.' WHERE id = 'w_cooking_B2_35';

