UPDATE words SET example_en_2 = 'She is passionate about gastronomy and travels to discover new cuisines.', example_ko_2 = '그녀는 미식학에 열정적이며 새로운 요리를 발견하기 위해 여행해요.', example_en_3 = 'Gastronomy explores the relationship between culture and food.', example_ko_3 = '미식학은 문화와 음식의 관계를 탐구해요.', example_en_4 = 'He studied gastronomy at a prestigious culinary institute in Lyon.', example_ko_4 = '그는 리옹의 명망 있는 요리 학원에서 미식학을 공부했어요.', example_en_5 = 'Modern gastronomy blends science and artistry in exciting ways.', example_ko_5 = '현대 미식학은 과학과 예술을 흥미로운 방식으로 결합해요.' WHERE id = 'w_cooking_C1_01';

UPDATE words SET example_en_2 = 'Proper mise en place makes service run smoothly even on busy nights.', example_ko_2 = '미장 플라스를 제대로 준비하면 바쁜 저녁에도 서비스가 원활하게 진행돼요.', example_en_3 = 'She arrived early to complete her mise en place before the kitchen opened.', example_ko_3 = '그녀는 주방이 열리기 전에 미장 플라스를 완료하기 위해 일찍 도착했어요.', example_en_4 = 'Mise en place is the foundation of professional kitchen organisation.', example_ko_4 = '미장 플라스는 전문 주방 조직의 기초예요.', example_en_5 = 'He taught his students that mise en place is a mindset, not just a task.', example_ko_5 = '그는 학생들에게 미장 플라스는 단순한 작업이 아닌 마음가짐이라고 가르쳤어요.' WHERE id = 'w_cooking_C1_02';

UPDATE words SET example_en_2 = 'She practised her julienne cuts until every piece was perfectly uniform.', example_ko_2 = '그녀는 모든 조각이 완벽하게 균일해질 때까지 줄리엔 썰기를 연습했어요.', example_en_3 = 'A julienne of carrots adds colour and texture to the stir-fry.', example_ko_3 = '당근을 줄리엔으로 썰면 볶음 요리에 색감과 질감이 더해져요.', example_en_4 = 'He julienned the courgette and served it as a light side dish.', example_ko_4 = '그는 애호박을 줄리엔으로 썰어 가벼운 사이드 디시로 냈어요.', example_en_5 = 'Julienne cuts are used in many classic French preparations.', example_ko_5 = '줄리엔 썰기는 많은 클래식 프렌치 요리에 사용돼요.' WHERE id = 'w_cooking_C1_03';

UPDATE words SET example_en_2 = 'The recipe called for a brunoise of shallots as the flavour base.', example_ko_2 = '레시피에는 맛의 기초로 샬롯 브루누아즈가 필요했어요.', example_en_3 = 'She spent twenty minutes carefully cutting the vegetables into a brunoise.', example_ko_3 = '그녀는 채소를 브루누아즈로 신중하게 써는 데 20분을 보냈어요.', example_en_4 = 'A fine brunoise of peppers gives the sauce a refined texture.', example_ko_4 = '고추의 정밀한 브루누아즈는 소스에 세련된 질감을 더해요.', example_en_5 = 'Mastering the brunoise cut requires a sharp knife and steady technique.', example_ko_5 = '브루누아즈 썰기를 마스터하려면 날카로운 칼과 안정된 기술이 필요해요.' WHERE id = 'w_cooking_C1_04';

UPDATE words SET example_en_2 = 'She prepared a chiffonade of basil to finish the pasta dish.', example_ko_2 = '그녀는 파스타 요리를 마무리하기 위해 바질 시포나드를 준비했어요.', example_en_3 = 'A chiffonade of mint adds a fresh finish to summer salads.', example_ko_3 = '민트 시포나드는 여름 샐러드에 신선한 마무리를 더해요.', example_en_4 = 'He used a chiffonade of spinach to garnish the soup bowl.', example_ko_4 = '그는 수프 그릇을 가니쉬하기 위해 시금치 시포나드를 사용했어요.', example_en_5 = 'The chiffonade technique involves rolling leaves tightly before slicing.', example_ko_5 = '시포나드 기술은 썰기 전에 잎을 단단히 말아 놓는 것을 포함해요.' WHERE id = 'w_cooking_C1_05';

UPDATE words SET example_en_2 = 'She made a dark roux by cooking flour and butter until it turned brown.', example_ko_2 = '그녀는 밀가루와 버터를 갈색이 될 때까지 볶아 진한 루를 만들었어요.', example_en_3 = 'A white roux is the starting point for a classic béchamel sauce.', example_ko_3 = '화이트 루는 클래식 베샤멜 소스의 출발점이에요.', example_en_4 = 'He added the hot milk to the roux gradually to avoid lumps.', example_ko_4 = '그는 덩어리가 생기지 않도록 뜨거운 우유를 루에 조금씩 넣었어요.', example_en_5 = 'The roux must be cooked long enough to remove the raw flour taste.', example_ko_5 = '루는 밀가루의 날 냄새를 없애기 위해 충분히 오래 조리해야 해요.' WHERE id = 'w_cooking_C1_06';

UPDATE words SET example_en_2 = 'A velouté is one of the five classic French mother sauces.', example_ko_2 = '벨루테는 다섯 가지 클래식 프렌치 마더 소스 중 하나예요.', example_en_3 = 'She made a chicken velouté to serve with the roasted breast.', example_ko_3 = '그녀는 구운 가슴살과 함께 낼 치킨 벨루테를 만들었어요.', example_en_4 = 'A well-made velouté should be silky, smooth, and lightly flavoured.', example_ko_4 = '잘 만든 벨루테는 비단처럼 부드럽고, 매끄럽고, 은은한 맛이 나야 해요.', example_en_5 = 'Velouté is made from a light stock thickened with a blonde roux.', example_ko_5 = '벨루테는 블론드 루로 걸쭉하게 만든 맑은 육수로 만들어요.' WHERE id = 'w_cooking_C1_07';

UPDATE words SET example_en_2 = 'Béchamel is used as a base for lasagne and other baked pasta dishes.', example_ko_2 = '베샤멜은 라자냐 및 다른 구운 파스타 요리의 기본으로 사용돼요.', example_en_3 = 'She whisked the béchamel constantly to keep it smooth.', example_ko_3 = '그녀는 베샤멜을 매끄럽게 유지하기 위해 계속 거품기로 저었어요.', example_en_4 = 'Adding cheese to a béchamel creates a Mornay sauce.', example_ko_4 = '베샤멜에 치즈를 더하면 모르네 소스가 돼요.', example_en_5 = 'A properly made béchamel should coat the back of a spoon.', example_ko_5 = '제대로 만든 베샤멜은 숟가락 뒷면에 코팅돼야 해요.' WHERE id = 'w_cooking_C1_08';

UPDATE words SET example_en_2 = 'Espagnole is a rich brown sauce made from a veal or beef stock base.', example_ko_2 = '에스파뇰은 송아지 또는 쇠고기 육수를 베이스로 한 진한 갈색 소스예요.', example_en_3 = 'She reduced the espagnole to make a rich demi-glace.', example_ko_3 = '그녀는 진한 드미글라스를 만들기 위해 에스파뇰을 리덕션했어요.', example_en_4 = 'Espagnole is one of the most complex of the French mother sauces.', example_ko_4 = '에스파뇰은 프랑스 마더 소스 중 가장 복잡한 것 중 하나예요.', example_en_5 = 'A dark, flavourful mirepoix forms the base of a traditional espagnole.', example_ko_5 = '짙고 풍미 있는 미르푸아는 전통적인 에스파뇰의 기초를 형성해요.' WHERE id = 'w_cooking_C1_09';

UPDATE words SET example_en_2 = 'She whisked hollandaise over a bain-marie to prevent it from curdling.', example_ko_2 = '그녀는 홀랜다이즈가 굳지 않도록 중탕으로 거품기로 저었어요.', example_en_3 = 'He drizzled warm hollandaise over the eggs Benedict.', example_ko_3 = '그는 에그 베네딕트 위에 따뜻한 홀랜다이즈를 뿌렸어요.', example_en_4 = 'Hollandaise is an emulsified sauce made from egg yolks and clarified butter.', example_ko_4 = '홀랜다이즈는 달걀 노른자와 정제 버터로 만든 유화 소스예요.', example_en_5 = 'Temperature control is essential when making hollandaise from scratch.', example_ko_5 = '홀랜다이즈를 처음부터 만들 때는 온도 조절이 매우 중요해요.' WHERE id = 'w_cooking_C1_10';

UPDATE words SET example_en_2 = 'The restaurant uses a sous vide machine to cook fish at a precise temperature.', example_ko_2 = '그 식당은 정확한 온도에서 생선을 조리하기 위해 수비드 기계를 사용해요.', example_en_3 = 'She prepared the duck legs sous vide for seventy-two hours.', example_ko_3 = '그녀는 오리 다리를 72시간 동안 수비드로 조리했어요.', example_en_4 = 'Sous vide ensures that proteins are cooked evenly from edge to centre.', example_ko_4 = '수비드는 단백질이 가장자리부터 중심까지 고르게 조리되도록 해요.', example_en_5 = 'After sous vide cooking, he seared the steak for a crispy crust.', example_ko_5 = '수비드 조리 후 그는 바삭한 크러스트를 위해 스테이크를 시어링했어요.' WHERE id = 'w_cooking_C1_11';

UPDATE words SET example_en_2 = 'She prepared a duck confit by slow-cooking the legs in their own fat.', example_ko_2 = '그녀는 오리 다리를 자체 지방에서 천천히 조리해 콩피를 만들었어요.', example_en_3 = 'Confit garlic is sweeter and mellower than raw garlic.', example_ko_3 = '콩피 마늘은 생 마늘보다 더 달콤하고 부드러워요.', example_en_4 = 'He served the confit duck with a cherry reduction sauce.', example_ko_4 = '그는 체리 리덕션 소스와 함께 콩피 오리를 냈어요.', example_en_5 = 'Confit is both a preservation method and a cooking technique.', example_ko_5 = '콩피는 보존 방법이자 조리 기술이에요.' WHERE id = 'w_cooking_C1_12';

UPDATE words SET example_en_2 = 'The chef prepared a smooth chicken liver terrine with cognac and thyme.', example_ko_2 = '셰프는 코냑과 타임으로 부드러운 닭 간 테린을 준비했어요.', example_en_3 = 'She served slices of terrine with cornichons and crusty bread.', example_ko_3 = '그녀는 코니숑과 바삭한 빵과 함께 테린을 슬라이스해서 냈어요.', example_en_4 = 'A terrine must be pressed and chilled overnight to set properly.', example_ko_4 = '테린은 제대로 굳히기 위해 하룻밤 동안 눌러서 냉장 보관해야 해요.', example_en_5 = 'A vegetable terrine makes an elegant and colourful starter.', example_ko_5 = '채소 테린은 우아하고 색채가 풍부한 전채 요리가 돼요.' WHERE id = 'w_cooking_C1_13';

UPDATE words SET example_en_2 = 'She made a classic Peruvian ceviche with lime juice and chilli.', example_ko_2 = '그녀는 라임즙과 칠리로 클래식 페루 세비체를 만들었어요.', example_en_3 = 'Fresh ceviche should be served immediately after preparation.', example_ko_3 = '신선한 세비체는 준비 직후 바로 제공해야 해요.', example_en_4 = 'The acid in the lime juice effectively cooks the fish in ceviche.', example_ko_4 = '라임즙의 산성이 세비체에서 생선을 효과적으로 익혀요.', example_en_5 = 'He added avocado and mango to his tropical ceviche.', example_ko_5 = '그는 트로피컬 세비체에 아보카도와 망고를 추가했어요.' WHERE id = 'w_cooking_C1_14';

UPDATE words SET example_en_2 = 'She sweated the mirepoix gently before adding the stock.', example_ko_2 = '그녀는 육수를 넣기 전에 미르푸아를 약불에서 살짝 볶았어요.', example_en_3 = 'A classic mirepoix consists of two parts onion to one part each of carrot and celery.', example_ko_3 = '클래식 미르푸아는 당근과 셀러리 각각 1에 대해 양파 2의 비율이에요.', example_en_4 = 'The mirepoix forms the flavour base of soups, stews, and braises.', example_ko_4 = '미르푸아는 수프, 스튜, 브레이징의 맛 기초를 형성해요.', example_en_5 = 'He roasted the mirepoix before adding it to the stock for extra depth.', example_ko_5 = '그는 더 깊은 맛을 위해 육수에 넣기 전에 미르푸아를 구웠어요.' WHERE id = 'w_cooking_C1_15';

UPDATE words SET example_en_2 = 'She tied a bouquet garni with string and removed it before serving.', example_ko_2 = '그녀는 부케 가르니를 실로 묶었고 제공하기 전에 제거했어요.', example_en_3 = 'A bouquet garni typically contains thyme, bay leaf, and parsley stems.', example_ko_3 = '부케 가르니는 일반적으로 타임, 베이 잎, 파슬리 줄기를 포함해요.', example_en_4 = 'He used a muslin cloth to wrap the bouquet garni for the stew.', example_ko_4 = '그는 스튜를 위한 부케 가르니를 감싸는 데 무명천을 사용했어요.', example_en_5 = 'The bouquet garni infuses the dish with a subtle herbal fragrance.', example_ko_5 = '부케 가르니는 요리에 은은한 허브 향기를 우려내요.' WHERE id = 'w_cooking_C1_16';

UPDATE words SET example_en_2 = 'She dehydrated sliced strawberries to use as a crispy dessert garnish.', example_ko_2 = '그녀는 바삭한 디저트 가니쉬로 사용하기 위해 딸기 슬라이스를 탈수했어요.', example_en_3 = 'He dehydrated mushrooms to concentrate their umami flavour.', example_ko_3 = '그는 버섯의 우마미 풍미를 농축시키기 위해 버섯을 탈수했어요.', example_en_4 = 'A dehydrator makes it easy to preserve herbs and seasonal fruits at home.', example_ko_4 = '탈수기는 집에서 허브와 제철 과일을 쉽게 보존할 수 있게 해줘요.', example_en_5 = 'Dehydrated vegetable powders are used to add intense colour and flavour.', example_ko_5 = '탈수 채소 파우더는 강렬한 색과 풍미를 더하는 데 사용돼요.' WHERE id = 'w_cooking_C1_17';

UPDATE words SET example_en_2 = 'The chef used spherification to create liquid olive oil pearls.', example_ko_2 = '셰프는 액체 올리브 오일 펄을 만들기 위해 구형화를 사용했어요.', example_en_3 = 'She learned spherification as part of her molecular gastronomy training.', example_ko_3 = '그녀는 분자 요리학 훈련의 일환으로 구형화를 배웠어요.', example_en_4 = 'Spherification creates small, gel-coated spheres that burst in the mouth.', example_ko_4 = '구형화는 입 안에서 터지는 작은 젤 코팅 구체를 만들어요.', example_en_5 = 'Calcium chloride and sodium alginate are used in the spherification process.', example_ko_5 = '염화칼슘과 알긴산나트륨은 구형화 과정에서 사용돼요.' WHERE id = 'w_cooking_C1_18';

UPDATE words SET example_en_2 = 'The stability of an emulsion depends on the ratio of oil to water.', example_ko_2 = '유화의 안정성은 오일 대 물의 비율에 달려 있어요.', example_en_3 = 'Mayonnaise is a classic example of a stable oil-in-water emulsion.', example_ko_3 = '마요네즈는 안정적인 수중유 유화의 클래식 예예요.', example_en_4 = 'Without an emulsifier, the oil and vinegar in a dressing will separate quickly.', example_ko_4 = '유화제 없이는 드레싱의 오일과 식초가 빠르게 분리돼요.', example_en_5 = 'She used mustard as an emulsifier to stabilise the vinaigrette.', example_ko_5 = '그녀는 비네그레트를 안정화하기 위해 머스타드를 유화제로 사용했어요.' WHERE id = 'w_cooking_C1_19';

UPDATE words SET example_en_2 = 'The chef created a saffron foam to garnish the risotto.', example_ko_2 = '셰프는 리조또를 가니쉬하기 위해 사프란 폼을 만들었어요.', example_en_3 = 'She made a lemon foam using a cream charger and citrus juice.', example_ko_3 = '그녀는 크림 카트리지와 시트러스 즙을 이용해 레몬 폼을 만들었어요.', example_en_4 = 'Light foams add texture and flavour without heaviness to a dish.', example_ko_4 = '가벼운 폼은 요리에 무거움 없이 질감과 풍미를 더해요.', example_en_5 = 'Culinary foam was popularised by chefs experimenting with modern techniques.', example_ko_5 = '요리 폼은 현대적 기술을 실험하는 셰프들에 의해 대중화됐어요.' WHERE id = 'w_cooking_C1_20';

UPDATE words SET example_en_2 = 'She used agar-agar to create a gel that held its shape at room temperature.', example_ko_2 = '그녀는 실온에서 형태를 유지하는 젤을 만들기 위해 아가-아가를 사용했어요.', example_en_3 = 'A pea gel was set around the dish to add a sweet, vivid element.', example_ko_3 = '달콤하고 선명한 요소를 더하기 위해 완두콩 젤을 요리 주위에 굳혔어요.', example_en_4 = 'He prepared a tomato water gel to garnish the caprese salad.', example_ko_4 = '그는 카프레제 샐러드를 가니쉬하기 위해 토마토 워터 젤을 준비했어요.', example_en_5 = 'Hydrocolloids like gelatin and agar are used to create culinary gels.', example_ko_5 = '젤라틴과 아가 같은 하이드로콜로이드는 요리용 젤을 만드는 데 사용돼요.' WHERE id = 'w_cooking_C1_21';

UPDATE words SET example_en_2 = 'She discovered molecular gastronomy while watching a documentary.', example_ko_2 = '그녀는 다큐멘터리를 보다가 분자 요리학을 발견했어요.', example_en_3 = 'Molecular gastronomy applies scientific methods to transform food textures.', example_ko_3 = '분자 요리학은 과학적 방법을 적용해 음식의 질감을 변환해요.', example_en_4 = 'He trained under a chef who specialised in molecular gastronomy.', example_ko_4 = '그는 분자 요리학을 전문으로 하는 셰프 밑에서 훈련했어요.', example_en_5 = 'Molecular gastronomy uses tools like liquid nitrogen and centrifuges in cooking.', example_ko_5 = '분자 요리학은 요리에서 액체 질소와 원심 분리기 같은 도구를 사용해요.' WHERE id = 'w_cooking_C1_22';

UPDATE words SET example_en_2 = 'She added kombu to the broth for natural umami enhancement.', example_ko_2 = '그녀는 자연적인 우마미 강화를 위해 육수에 다시마를 넣었어요.', example_en_3 = 'Umami enhancement is achieved by combining several glutamate-rich ingredients.', example_ko_3 = '우마미 강화는 여러 글루타민산이 풍부한 재료를 조합함으로써 이루어져요.', example_en_4 = 'Fermenting soy beans leads to a dramatic umami enhancement in the paste.', example_ko_4 = '대두를 발효시키면 된장의 우마미가 크게 강화돼요.', example_en_5 = 'A dash of fish sauce provides significant umami enhancement to vegetable dishes.', example_ko_5 = '피시 소스 한 방울은 채소 요리에 상당한 우마미 강화를 제공해요.' WHERE id = 'w_cooking_C1_23';

UPDATE words SET example_en_2 = 'The Maillard reaction gives roasted coffee its characteristic brown colour.', example_ko_2 = '마이야르 반응은 로스팅된 커피에 특유의 갈색을 부여해요.', example_en_3 = 'She seared the meat at high heat to trigger the Maillard reaction.', example_ko_3 = '그녀는 마이야르 반응을 일으키기 위해 고온에서 고기를 시어링했어요.', example_en_4 = 'The Maillard reaction occurs between amino acids and reducing sugars.', example_ko_4 = '마이야르 반응은 아미노산과 환원당 사이에서 발생해요.', example_en_5 = 'Without the Maillard reaction, baked goods would lack their golden crust.', example_ko_5 = '마이야르 반응 없이는 구운 식품에 황금빛 크러스트가 생기지 않아요.' WHERE id = 'w_cooking_C1_24';

UPDATE words SET example_en_2 = 'Caramelization occurs when sugar is heated above 160°C.', example_ko_2 = '캐러멜화는 설탕이 160°C 이상으로 가열될 때 발생해요.', example_en_3 = 'The caramelization of onions takes patience and a low, steady heat.', example_ko_3 = '양파의 캐러멜화에는 인내심과 낮고 일정한 온도가 필요해요.', example_en_4 = 'Caramelization creates hundreds of new flavour compounds in the sugar.', example_ko_4 = '캐러멜화는 설탕에서 수백 가지의 새로운 맛 화합물을 만들어내요.', example_en_5 = 'She used caramelization to develop a rich sauce from cherry tomatoes.', example_ko_5 = '그녀는 방울토마토에서 진한 소스를 만들기 위해 캐러멜화를 활용했어요.' WHERE id = 'w_cooking_C1_25';

UPDATE words SET example_en_2 = 'Understanding the thermodynamics of cooking helps chefs control results precisely.', example_ko_2 = '요리의 열역학을 이해하면 셰프가 결과를 정밀하게 제어하는 데 도움이 돼요.', example_en_3 = 'The thermodynamics of cooking explains why different methods produce different textures.', example_ko_3 = '요리의 열역학은 왜 다른 방법이 다른 질감을 만들어내는지 설명해요.', example_en_4 = 'She studied the thermodynamics of cooking to improve her baking results.', example_ko_4 = '그녀는 베이킹 결과를 향상시키기 위해 요리의 열역학을 공부했어요.', example_en_5 = 'Heat transfer is central to the thermodynamics of cooking.', example_ko_5 = '열 전달은 요리의 열역학의 핵심이에요.' WHERE id = 'w_cooking_C1_26';

UPDATE words SET example_en_2 = 'She macerated the strawberries in sugar and orange juice for an hour.', example_ko_2 = '그녀는 딸기를 설탕과 오렌지 주스에 1시간 동안 침지했어요.', example_en_3 = 'Maceration softens the fruit and draws out its natural juices.', example_ko_3 = '침지는 과일을 부드럽게 하고 자연 즙을 끌어내요.', example_en_4 = 'He macerated dried apricots in brandy to use in a Christmas cake.', example_ko_4 = '그는 크리스마스 케이크에 사용하기 위해 말린 살구를 브랜디에 침지했어요.', example_en_5 = 'Maceration is commonly used in both cooking and winemaking.', example_ko_5 = '침지는 요리와 와인 양조 모두에서 일반적으로 사용돼요.' WHERE id = 'w_cooking_C1_27';

UPDATE words SET example_en_2 = 'Osmosis draws water out of vegetables when they are salted.', example_ko_2 = '삼투압은 채소에 소금을 뿌릴 때 수분을 끌어내요.', example_en_3 = 'She used osmosis to remove excess moisture from sliced courgette.', example_ko_3 = '그녀는 애호박 슬라이스에서 여분의 수분을 제거하기 위해 삼투압을 활용했어요.', example_en_4 = 'Osmosis is the reason cucumbers shrink when left in a salt brine.', example_ko_4 = '삼투압이 오이를 소금물에 담가두면 오이가 작아지는 이유예요.', example_en_5 = 'Understanding osmosis helps cooks control the texture of cured foods.', example_ko_5 = '삼투압을 이해하면 요리사가 절인 음식의 질감을 조절하는 데 도움이 돼요.' WHERE id = 'w_cooking_C1_28';

UPDATE words SET example_en_2 = 'Vanillin is the primary flavor compound responsible for vanilla''s aroma.', example_ko_2 = '바닐린은 바닐라 향기를 담당하는 주요 향미 화합물이에요.', example_en_3 = 'Different flavor compounds interact to create a wine''s unique profile.', example_ko_3 = '다양한 향미 화합물이 상호작용하여 와인 고유의 특성을 만들어요.', example_en_4 = 'She studied which flavor compounds develop during the Maillard reaction.', example_ko_4 = '그녀는 마이야르 반응 중에 어떤 향미 화합물이 생성되는지 연구했어요.', example_en_5 = 'Roasting increases the concentration of flavor compounds in coffee beans.', example_ko_5 = '로스팅은 커피 원두의 향미 화합물 농도를 높여요.' WHERE id = 'w_cooking_C1_29';

UPDATE words SET example_en_2 = 'The volatile aroma of fresh herbs disappears quickly when overcooked.', example_ko_2 = '신선한 허브의 휘발성 향기는 너무 오래 조리하면 빠르게 사라져요.', example_en_3 = 'She added the lemon zest at the end to preserve its volatile aroma.', example_ko_3 = '그녀는 휘발성 향기를 보존하기 위해 마지막에 레몬 껍질을 넣었어요.', example_en_4 = 'The volatile aroma compounds in wine evaporate when the glass is warmed.', example_ko_4 = '와인의 휘발성 향기 화합물은 잔이 따뜻해질 때 증발해요.', example_en_5 = 'Toast releases volatile aroma molecules that trigger appetite.', example_ko_5 = '토스트는 식욕을 자극하는 휘발성 향기 분자를 방출해요.' WHERE id = 'w_cooking_C1_30';

UPDATE words SET example_en_2 = 'She developed a refined palate through years of tasting wine and food.', example_ko_2 = '그녀는 수년간 와인과 음식을 맛보면서 세련된 미각을 발달시켰어요.', example_en_3 = 'A chef with a good palate can identify every ingredient in a dish.', example_ko_3 = '훌륭한 미각을 가진 셰프는 요리의 모든 재료를 식별할 수 있어요.', example_en_4 = 'He trained his palate by tasting the same dish prepared in different ways.', example_ko_4 = '그는 다양한 방법으로 준비된 같은 요리를 맛봄으로써 미각을 훈련했어요.', example_en_5 = 'A sensitive palate is an essential asset for any professional cook.', example_ko_5 = '민감한 미각은 모든 전문 요리사에게 필수적인 자산이에요.' WHERE id = 'w_cooking_C1_31';

UPDATE words SET example_en_2 = 'She underwent sensory evaluation training at a flavour laboratory.', example_ko_2 = '그녀는 향미 실험실에서 감각 평가 훈련을 받았어요.', example_en_3 = 'Sensory evaluation panels assess food for taste, texture, and appearance.', example_ko_3 = '감각 평가 패널은 맛, 질감, 외관에 대해 식품을 평가해요.', example_en_4 = 'He used sensory evaluation to compare two versions of the same sauce.', example_ko_4 = '그는 같은 소스의 두 가지 버전을 비교하기 위해 감각 평가를 사용했어요.', example_en_5 = 'Sensory evaluation combines subjective taste tests with objective data.', example_ko_5 = '감각 평가는 주관적인 맛 테스트와 객관적인 데이터를 결합해요.' WHERE id = 'w_cooking_C1_32';

UPDATE words SET example_en_2 = 'She pursued food science to better understand the chemistry behind cooking.', example_ko_2 = '그녀는 요리 뒤에 숨겨진 화학을 더 잘 이해하기 위해 식품 과학을 공부했어요.', example_en_3 = 'Food science explains why bread rises, milk curdles, and jam sets.', example_ko_3 = '식품 과학은 왜 빵이 부풀고, 우유가 응고되고, 잼이 굳는지를 설명해요.', example_en_4 = 'He applied food science principles to improve shelf life in his bakery.', example_ko_4 = '그는 빵집의 유통 기한을 개선하기 위해 식품 과학 원리를 적용했어요.', example_en_5 = 'Food science and culinary art are increasingly intersecting disciplines.', example_ko_5 = '식품 과학과 요리 예술은 점점 더 교차하는 학문 분야예요.' WHERE id = 'w_cooking_C1_33';

UPDATE words SET example_en_2 = 'She analysed the nutritional profile of her recipes to meet dietary guidelines.', example_ko_2 = '그녀는 식이 지침을 충족시키기 위해 레시피의 영양 프로파일을 분석했어요.', example_en_3 = 'The nutritional profile of quinoa makes it a complete protein source.', example_ko_3 = '퀴노아의 영양 프로파일은 완전한 단백질 공급원으로 만들어요.', example_en_4 = 'He modified the dish to improve its nutritional profile without losing flavour.', example_ko_4 = '그는 풍미를 잃지 않으면서 영양 프로파일을 개선하기 위해 요리를 수정했어요.', example_en_5 = 'Cooking methods can significantly alter the nutritional profile of ingredients.', example_ko_5 = '조리 방법은 재료의 영양 프로파일을 크게 바꿀 수 있어요.' WHERE id = 'w_cooking_C1_34';

UPDATE words SET example_en_2 = 'She wrote a book celebrating the culinary tradition of her home region.', example_ko_2 = '그녀는 고향 지역의 요리 전통을 기리는 책을 썼어요.', example_en_3 = 'The culinary tradition of fermentation connects generations in Korea.', example_ko_3 = '발효의 요리 전통은 한국에서 세대를 연결해요.', example_en_4 = 'He worked hard to preserve the culinary tradition of his grandmother.', example_ko_4 = '그는 할머니의 요리 전통을 보존하기 위해 열심히 노력했어요.', example_en_5 = 'Culinary traditions reflect the history, climate, and culture of a place.', example_ko_5 = '요리 전통은 한 장소의 역사, 기후, 문화를 반영해요.' WHERE id = 'w_cooking_C1_35';

-- C2
UPDATE words SET example_en_2 = 'The panel assessed the wine using organoleptic criteria including colour, aroma, and taste.', example_ko_2 = '패널은 색, 향기, 맛을 포함한 오르가노렙틱 기준을 사용하여 와인을 평가했어요.', example_en_3 = 'Organoleptic evaluation requires trained assessors with calibrated sensory skills.', example_ko_3 = '오르가노렙틱 평가는 교정된 감각 기술을 가진 훈련된 평가자가 필요해요.', example_en_4 = 'She designed an organoleptic profile for the new cheese to guide production.', example_ko_4 = '그녀는 생산 지침을 제공하기 위해 새 치즈의 오르가노렙틱 프로파일을 설계했어요.', example_en_5 = 'Changes in processing temperature affected the organoleptic properties of the product.', example_ko_5 = '처리 온도의 변화가 제품의 오르가노렙틱 특성에 영향을 미쳤어요.' WHERE id = 'w_cooking_C2_01';

UPDATE words SET example_en_2 = 'Oleic acid makes up the majority of the fatty acids in olive oil.', example_ko_2 = '올레산은 올리브 오일 내 지방산의 대부분을 차지해요.', example_en_3 = 'Foods rich in oleic acid have been associated with reduced cardiovascular risk.', example_ko_3 = '올레산이 풍부한 식품은 심혈관 위험 감소와 관련이 있어요.', example_en_4 = 'Avocados contain a high proportion of oleic acid among their lipid content.', example_ko_4 = '아보카도는 지질 함량 중 올레산의 비율이 높아요.', example_en_5 = 'The stability of oleic acid at high temperatures makes it ideal for frying.', example_ko_5 = '고온에서 올레산의 안정성은 튀김에 이상적으로 만들어요.' WHERE id = 'w_cooking_C2_02';

UPDATE words SET example_en_2 = 'Anthocyanin gives blueberries, red cabbage, and purple rice their vivid hues.', example_ko_2 = '안토시아닌은 블루베리, 적양배추, 보라색 쌀에 선명한 색을 부여해요.', example_en_3 = 'The anthocyanin content of a berry decreases significantly when overcooked.', example_ko_3 = '과도하게 조리하면 베리의 안토시아닌 함량이 크게 감소해요.', example_en_4 = 'Anthocyanin acts as an antioxidant and has anti-inflammatory properties.', example_ko_4 = '안토시아닌은 항산화제로 작용하며 항염증 특성을 가지고 있어요.', example_en_5 = 'She added purple sweet potato to boost the anthocyanin level in her smoothie.', example_ko_5 = '그녀는 스무디의 안토시아닌 수치를 높이기 위해 자색 고구마를 추가했어요.' WHERE id = 'w_cooking_C2_03';

UPDATE words SET example_en_2 = 'Green tea is especially rich in a polyphenol called epigallocatechin gallate.', example_ko_2 = '녹차는 특히 에피갈로카테킨 갈레이트라는 폴리페놀이 풍부해요.', example_en_3 = 'Polyphenol-rich foods like berries and dark chocolate support heart health.', example_ko_3 = '베리와 다크 초콜릿 같은 폴리페놀이 풍부한 식품은 심장 건강을 지원해요.', example_en_4 = 'The polyphenol content of olive oil is higher in extra-virgin varieties.', example_ko_4 = '올리브 오일의 폴리페놀 함량은 엑스트라 버진 품종에서 더 높아요.', example_en_5 = 'Processing methods can destroy much of the polyphenol content in raw ingredients.', example_ko_5 = '가공 방법은 원재료의 폴리페놀 함량을 많이 파괴할 수 있어요.' WHERE id = 'w_cooking_C2_04';

UPDATE words SET example_en_2 = 'Vitamin E is a fat-soluble antioxidant found in nuts and vegetable oils.', example_ko_2 = '비타민 E는 견과류와 식물성 오일에서 발견되는 지용성 항산화제예요.', example_en_3 = 'She added berries to her diet to increase her antioxidant intake.', example_ko_3 = '그녀는 항산화제 섭취를 늘리기 위해 식단에 베리를 추가했어요.', example_en_4 = 'Antioxidants in food help to neutralise free radicals in the body.', example_ko_4 = '식품의 항산화제는 체내 자유 라디칼을 중화하는 데 도움이 돼요.', example_en_5 = 'Cooking at high temperatures can reduce the antioxidant potential of vegetables.', example_ko_5 = '고온에서 조리하면 채소의 항산화 잠재력이 감소할 수 있어요.' WHERE id = 'w_cooking_C2_05';

UPDATE words SET example_en_2 = 'The bioavailability of iron from plant sources is lower than from meat.', example_ko_2 = '식물성 공급원에서 철분의 생체 이용 가능성은 고기보다 낮아요.', example_en_3 = 'Adding vitamin C to a meal can increase the bioavailability of non-haem iron.', example_ko_3 = '식사에 비타민 C를 추가하면 비헴 철분의 생체 이용 가능성을 높일 수 있어요.', example_en_4 = 'Fermentation can significantly improve the bioavailability of nutrients in grains.', example_ko_4 = '발효는 곡물의 영양소 생체 이용 가능성을 크게 개선할 수 있어요.', example_en_5 = 'Cooking methods affect the bioavailability of vitamins and minerals in vegetables.', example_ko_5 = '조리 방법은 채소의 비타민과 미네랄의 생체 이용 가능성에 영향을 줘요.' WHERE id = 'w_cooking_C2_06';

UPDATE words SET example_en_2 = 'Foods with a low glycemic index release energy slowly and steadily.', example_ko_2 = '혈당 지수가 낮은 식품은 에너지를 천천히 꾸준하게 방출해요.', example_en_3 = 'She chose lentils over white rice because of their lower glycemic index.', example_ko_3 = '그녀는 낮은 혈당 지수 때문에 흰 쌀 대신 렌틸콩을 선택했어요.', example_en_4 = 'Cooking pasta al dente results in a lower glycemic index than overcooking it.', example_ko_4 = '파스타를 알 덴테로 조리하면 과도하게 조리하는 것보다 혈당 지수가 낮아요.', example_en_5 = 'The glycemic index is an important tool for managing blood sugar levels.', example_ko_5 = '혈당 지수는 혈당 수치를 관리하는 데 중요한 도구예요.' WHERE id = 'w_cooking_C2_07';

UPDATE words SET example_en_2 = 'Lipid oxidation causes fats to become rancid when exposed to air and heat.', example_ko_2 = '지질 산화는 공기와 열에 노출될 때 지방이 산패되게 해요.', example_en_3 = 'She stored the nuts in an airtight container to prevent lipid oxidation.', example_ko_3 = '그녀는 지질 산화를 방지하기 위해 견과류를 밀폐 용기에 보관했어요.', example_en_4 = 'Antioxidants in the coating slow down lipid oxidation in fried products.', example_ko_4 = '코팅의 항산화제는 튀긴 제품의 지질 산화를 늦춰요.', example_en_5 = 'Refrigeration reduces the rate of lipid oxidation in fatty fish.', example_ko_5 = '냉장 보관은 기름진 생선의 지질 산화 속도를 줄여요.' WHERE id = 'w_cooking_C2_08';

UPDATE words SET example_en_2 = 'Protein denaturation occurs when heat breaks the bonds holding protein structures together.', example_ko_2 = '단백질 변성은 열이 단백질 구조를 유지하는 결합을 끊을 때 발생해요.', example_en_3 = 'The protein denaturation in a cooked egg white makes it firm and opaque.', example_ko_3 = '익힌 달걀 흰자의 단백질 변성은 그것을 단단하고 불투명하게 만들어요.', example_en_4 = 'Acid can cause protein denaturation, which is why ceviche fish becomes firm.', example_ko_4 = '산성은 단백질 변성을 일으킬 수 있으며, 이것이 세비체의 생선이 단단해지는 이유예요.', example_en_5 = 'She studied protein denaturation to improve the texture of her products.', example_ko_5 = '그녀는 제품의 질감을 개선하기 위해 단백질 변성을 연구했어요.' WHERE id = 'w_cooking_C2_09';

UPDATE words SET example_en_2 = 'Starch gelatinization is what makes a sauce thicken when heated.', example_ko_2 = '전분 젤라틴화가 소스를 가열할 때 걸쭉하게 만드는 것이에요.', example_en_3 = 'She understood starch gelatinization well enough to use different starches interchangeably.', example_ko_3 = '그녀는 전분 젤라틴화를 충분히 이해하여 다양한 전분을 상호 교환적으로 사용했어요.', example_en_4 = 'Starch gelatinization requires adequate water and heat to occur.', example_ko_4 = '전분 젤라틴화가 일어나려면 충분한 수분과 열이 필요해요.', example_en_5 = 'The temperature at which starch gelatinization begins varies among different starches.', example_ko_5 = '전분 젤라틴화가 시작되는 온도는 다양한 전분에 따라 다르게 달라요.' WHERE id = 'w_cooking_C2_10';

UPDATE words SET example_en_2 = 'Fermentation chemistry explains how bacteria convert sugars into lactic acid.', example_ko_2 = '발효 화학은 박테리아가 어떻게 당을 젖산으로 변환하는지 설명해요.', example_en_3 = 'She studied fermentation chemistry to perfect her sourdough bread.', example_ko_3 = '그녀는 사워도우 빵을 완성하기 위해 발효 화학을 공부했어요.', example_en_4 = 'Understanding fermentation chemistry allows brewers to control flavour outcomes.', example_ko_4 = '발효 화학을 이해하면 양조업자가 맛 결과를 제어할 수 있어요.', example_en_5 = 'Fermentation chemistry underpins the production of cheese, wine, and vinegar.', example_ko_5 = '발효 화학은 치즈, 와인, 식초 생산의 기초를 이루어요.' WHERE id = 'w_cooking_C2_11';

UPDATE words SET example_en_2 = 'Enzymatic browning causes cut apples to turn brown within minutes.', example_ko_2 = '효소적 갈변은 자른 사과를 몇 분 안에 갈색으로 변하게 해요.', example_en_3 = 'Adding lemon juice inhibits enzymatic browning in avocado dishes.', example_ko_3 = '레몬즙을 추가하면 아보카도 요리에서 효소적 갈변을 억제해요.', example_en_4 = 'Blanching deactivates the enzymes responsible for enzymatic browning.', example_ko_4 = '데치기는 효소적 갈변을 일으키는 효소를 비활성화해요.', example_en_5 = 'Enzymatic browning is undesirable in some products but essential in others like tea.', example_ko_5 = '효소적 갈변은 일부 제품에서는 바람직하지 않지만 차와 같은 다른 것에서는 필수적이에요.' WHERE id = 'w_cooking_C2_12';

UPDATE words SET example_en_2 = 'Non-enzymatic browning includes both the Maillard reaction and caramelization.', example_ko_2 = '비효소적 갈변에는 마이야르 반응과 캐러멜화가 모두 포함돼요.', example_en_3 = 'She studied non-enzymatic browning to understand why baked goods develop colour.', example_ko_3 = '그녀는 구운 식품이 왜 색을 내는지 이해하기 위해 비효소적 갈변을 연구했어요.', example_en_4 = 'Non-enzymatic browning also generates aromatic compounds that enhance flavour.', example_ko_4 = '비효소적 갈변은 또한 풍미를 향상시키는 방향성 화합물을 생성해요.', example_en_5 = 'Control of temperature and pH affects the rate of non-enzymatic browning.', example_ko_5 = '온도와 pH의 제어는 비효소적 갈변의 속도에 영향을 줘요.' WHERE id = 'w_cooking_C2_13';

UPDATE words SET example_en_2 = 'Collagen hydrolysis during long cooking converts tough connective tissue into gelatin.', example_ko_2 = '긴 조리 중 콜라겐 가수분해는 질긴 결합 조직을 젤라틴으로 변환해요.', example_en_3 = 'She slow-cooked the oxtail to maximise collagen hydrolysis and produce a rich sauce.', example_ko_3 = '그녀는 콜라겐 가수분해를 최대화하고 진한 소스를 만들기 위해 소꼬리를 천천히 조리했어요.', example_en_4 = 'Collagen hydrolysis is the reason braised meat has a silky, mouth-coating texture.', example_ko_4 = '콜라겐 가수분해가 브레이징한 고기에 비단같이 입에 코팅되는 질감이 생기는 이유예요.', example_en_5 = 'Temperature and time are the key variables in controlling collagen hydrolysis.', example_ko_5 = '온도와 시간은 콜라겐 가수분해를 조절하는 핵심 변수예요.' WHERE id = 'w_cooking_C2_14';

UPDATE words SET example_en_2 = 'The emulsification physics of mayonnaise depend on the size of oil droplets.', example_ko_2 = '마요네즈의 유화 물리학은 오일 방울의 크기에 달려 있어요.', example_en_3 = 'She studied emulsification physics to understand why her sauces kept breaking.', example_ko_3 = '그녀는 소스가 왜 계속 분리되는지 이해하기 위해 유화 물리학을 공부했어요.', example_en_4 = 'Emulsification physics dictates the ratio of emulsifier to oil required for stability.', example_ko_4 = '유화 물리학은 안정성을 위해 필요한 유화제 대 오일의 비율을 결정해요.', example_en_5 = 'A high-speed blender exploits emulsification physics to create stable sauces quickly.', example_ko_5 = '고속 블렌더는 유화 물리학을 활용하여 안정적인 소스를 빠르게 만들어요.' WHERE id = 'w_cooking_C2_15';

UPDATE words SET example_en_2 = 'Lecithin from soy acts as a surfactant in many processed food products.', example_ko_2 = '대두에서 추출한 레시틴은 많은 가공 식품에서 계면활성제로 작용해요.', example_en_3 = 'A surfactant reduces the surface tension between oil and water in an emulsion.', example_ko_3 = '계면활성제는 유화에서 오일과 물 사이의 표면 장력을 줄여요.', example_en_4 = 'She used a food-grade surfactant to stabilise the foam on the dessert.', example_ko_4 = '그녀는 디저트 위의 폼을 안정화하기 위해 식품 등급 계면활성제를 사용했어요.', example_en_5 = 'Understanding how a surfactant works helps in developing new food textures.', example_ko_5 = '계면활성제가 어떻게 작용하는지 이해하면 새로운 식품 질감을 개발하는 데 도움이 돼요.' WHERE id = 'w_cooking_C2_16';

UPDATE words SET example_en_2 = 'Pectin is a hydrocolloid that gives jams and jellies their gel-like structure.', example_ko_2 = '펙틴은 잼과 젤리에 젤 같은 구조를 부여하는 하이드로콜로이드예요.', example_en_3 = 'She experimented with different hydrocolloids to find the best thickener for her sauce.', example_ko_3 = '그녀는 소스에 가장 적합한 농후제를 찾기 위해 다양한 하이드로콜로이드로 실험했어요.', example_en_4 = 'Hydrocolloids are essential ingredients in many modern culinary applications.', example_ko_4 = '하이드로콜로이드는 많은 현대 요리 응용 프로그램에서 필수 재료예요.', example_en_5 = 'Xanthan gum is a versatile hydrocolloid used in gluten-free baking.', example_ko_5 = '잔탄검은 글루텐 프리 베이킹에 사용되는 다용도 하이드로콜로이드예요.' WHERE id = 'w_cooking_C2_17';

UPDATE words SET example_en_2 = 'The rheology of a sauce determines how it will pour and coat food.', example_ko_2 = '소스의 레올로지는 소스가 어떻게 흘러내리고 음식에 코팅되는지를 결정해요.', example_en_3 = 'She studied the rheology of chocolate to improve its flow during moulding.', example_ko_3 = '그녀는 성형 중 흐름을 개선하기 위해 초콜릿의 레올로지를 연구했어요.', example_en_4 = 'Understanding rheology helps food scientists to design better textures.', example_ko_4 = '레올로지를 이해하면 식품 과학자들이 더 나은 질감을 설계하는 데 도움이 돼요.', example_en_5 = 'The rheology of dough changes significantly depending on the hydration level.', example_ko_5 = '반죽의 레올로지는 수분 수준에 따라 크게 달라져요.' WHERE id = 'w_cooking_C2_18';

UPDATE words SET example_en_2 = 'The viscosity of honey makes it ideal for slow drizzling over desserts.', example_ko_2 = '꿀의 점도는 디저트 위에 천천히 뿌리기에 이상적으로 만들어요.', example_en_3 = 'She adjusted the viscosity of the sauce by adding more stock.', example_ko_3 = '그녀는 육수를 더 넣어 소스의 점도를 조정했어요.', example_en_4 = 'Temperature significantly affects the viscosity of oils and fats.', example_ko_4 = '온도는 오일과 지방의 점도에 크게 영향을 미쳐요.', example_en_5 = 'Viscosity is a key parameter in designing pourable food products.', example_ko_5 = '점도는 쏟아 부을 수 있는 식품 제품을 설계하는 데 핵심 매개변수예요.' WHERE id = 'w_cooking_C2_19';

UPDATE words SET example_en_2 = 'The sensory threshold for bitterness is lower than for sweetness.', example_ko_2 = '쓴맛의 감각 역치는 단맛보다 낮아요.', example_en_3 = 'She measured the sensory threshold for saltiness in her new product.', example_ko_3 = '그녀는 새 제품의 짠맛 감각 역치를 측정했어요.', example_en_4 = 'The sensory threshold refers to the minimum concentration detectable by the palate.', example_ko_4 = '감각 역치는 미각으로 감지 가능한 최소 농도를 의미해요.', example_en_5 = 'Individual sensory thresholds vary widely due to genetics and experience.', example_ko_5 = '개인 감각 역치는 유전과 경험에 따라 크게 달라요.' WHERE id = 'w_cooking_C2_20';

UPDATE words SET example_en_2 = 'Each olfactory receptor in the nose is sensitive to specific aroma compounds.', example_ko_2 = '코의 각 후각 수용체는 특정 향기 화합물에 민감해요.', example_en_3 = 'The olfactory receptor system can distinguish thousands of different smells.', example_ko_3 = '후각 수용체 시스템은 수천 가지의 다른 냄새를 구별할 수 있어요.', example_en_4 = 'Damage to olfactory receptors can significantly impair flavour perception.', example_ko_4 = '후각 수용체 손상은 풍미 인식을 크게 손상시킬 수 있어요.', example_en_5 = 'She researched which olfactory receptors respond to vanilla compounds.', example_ko_5 = '그녀는 어떤 후각 수용체가 바닐라 화합물에 반응하는지 연구했어요.' WHERE id = 'w_cooking_C2_21';

UPDATE words SET example_en_2 = 'Gustatory receptors on the tongue detect the five basic tastes.', example_ko_2 = '혀의 미각 수용체는 다섯 가지 기본 맛을 감지해요.', example_en_3 = 'Gustatory perception can be influenced by smell, texture, and visual appearance.', example_ko_3 = '미각 인식은 냄새, 질감, 시각적 외모에 의해 영향을 받을 수 있어요.', example_en_4 = 'She studied gustatory science to understand consumer preferences.', example_ko_4 = '그녀는 소비자 선호도를 이해하기 위해 미각 과학을 공부했어요.', example_en_5 = 'The gustatory experience is incomplete without the contribution of olfaction.', example_ko_5 = '미각 경험은 후각의 기여 없이는 불완전해요.' WHERE id = 'w_cooking_C2_22';

UPDATE words SET example_en_2 = 'Retronasal olfaction is responsible for the flavour we perceive when chewing food.', example_ko_2 = '역후각은 음식을 씹을 때 우리가 인식하는 풍미를 담당해요.', example_en_3 = 'She explained that retronasal olfaction accounts for most of what we call "taste."', example_ko_3 = '그녀는 역후각이 우리가 "맛"이라고 부르는 것의 대부분을 차지한다고 설명했어요.', example_en_4 = 'A blocked nose reduces retronasal olfaction and makes food seem bland.', example_ko_4 = '코가 막히면 역후각이 감소하여 음식이 밍밍하게 느껴져요.', example_en_5 = 'Chewing slowly enhances retronasal olfaction by releasing more volatile aromas.', example_ko_5 = '천천히 씹으면 더 많은 휘발성 향기를 방출하여 역후각이 향상돼요.' WHERE id = 'w_cooking_C2_23';

UPDATE words SET example_en_2 = 'Flavour perception is a multimodal experience involving taste, smell, and touch.', example_ko_2 = '풍미 인식은 맛, 냄새, 촉감을 포함하는 다중 감각 경험이에요.', example_en_3 = 'She studied the psychology of flavour perception for her food science thesis.', example_ko_3 = '그녀는 식품 과학 논문을 위해 풍미 인식의 심리학을 공부했어요.', example_en_4 = 'Colour can influence flavour perception even without changing the actual taste.', example_ko_4 = '색상은 실제 맛을 바꾸지 않고도 풍미 인식에 영향을 줄 수 있어요.', example_en_5 = 'Context and expectation play a significant role in flavour perception.', example_ko_5 = '맥락과 기대는 풍미 인식에서 중요한 역할을 해요.' WHERE id = 'w_cooking_C2_24';

UPDATE words SET example_en_2 = 'The terroir of a vineyard is expressed in the mineral notes of its wine.', example_ko_2 = '포도원의 테루아는 와인의 미네랄 노트에서 표현돼요.', example_en_3 = 'Chefs are increasingly exploring terroir as a concept applied to food ingredients.', example_ko_3 = '셰프들은 점점 더 식재료에 적용되는 개념으로서 테루아를 탐구하고 있어요.', example_en_4 = 'The unique terroir of the Champagne region makes its wines difficult to replicate.', example_ko_4 = '샴페인 지역의 독특한 테루아는 그 와인을 복제하기 어렵게 만들어요.', example_en_5 = 'She argued that coffee grown at altitude develops a more complex terroir character.', example_ko_5 = '그녀는 고지대에서 재배된 커피가 더 복잡한 테루아 특성을 발달시킨다고 주장했어요.' WHERE id = 'w_cooking_C2_25';

UPDATE words SET example_en_2 = 'The provenance of ingredients is increasingly important to discerning consumers.', example_ko_2 = '재료의 출처는 까다로운 소비자들에게 점점 더 중요해지고 있어요.', example_en_3 = 'She clearly labelled the provenance of every ingredient on the menu.', example_ko_3 = '그녀는 메뉴에 모든 재료의 출처를 명확하게 표시했어요.', example_en_4 = 'The provenance of a dish can deeply influence how it is perceived.', example_ko_4 = '요리의 출처는 그것이 어떻게 인식되는지에 깊은 영향을 줄 수 있어요.', example_en_5 = 'Provenance traceability is a growing priority in global food supply chains.', example_ko_5 = '출처 추적 가능성은 글로벌 식품 공급망에서 점점 더 중요한 우선 사항이에요.' WHERE id = 'w_cooking_C2_26';

UPDATE words SET example_en_2 = 'The indigenous ingredient taro root is central to Hawaiian cooking.', example_ko_2 = '토착 재료인 토란은 하와이 요리의 중심이에요.', example_en_3 = 'She championed the use of indigenous ingredients to preserve culinary identity.', example_ko_3 = '그녀는 요리 정체성을 보존하기 위해 토착 재료 사용을 옹호했어요.', example_en_4 = 'Using indigenous ingredients supports local biodiversity and farming communities.', example_ko_4 = '토착 재료를 사용하면 지역 생물 다양성과 농업 공동체를 지원해요.', example_en_5 = 'He studied indigenous ingredients from the Amazon as part of his research.', example_ko_5 = '그는 연구의 일환으로 아마존의 토착 재료를 연구했어요.' WHERE id = 'w_cooking_C2_27';

UPDATE words SET example_en_2 = 'Food sovereignty gives communities the right to define their own food systems.', example_ko_2 = '식량 주권은 공동체가 자체 식품 시스템을 정의할 권리를 부여해요.', example_en_3 = 'She wrote her thesis on food sovereignty and smallholder farming in Asia.', example_ko_3 = '그녀는 아시아의 식량 주권과 소농 농업에 관한 논문을 썼어요.', example_en_4 = 'Food sovereignty movements challenge the dominance of industrial agriculture.', example_ko_4 = '식량 주권 운동은 산업 농업의 지배에 도전해요.', example_en_5 = 'Protecting indigenous seeds is a core principle of food sovereignty.', example_ko_5 = '토착 씨앗 보호는 식량 주권의 핵심 원칙이에요.' WHERE id = 'w_cooking_C2_28';

UPDATE words SET example_en_2 = 'She incorporated culinary anthropology into her research on street food culture.', example_ko_2 = '그녀는 길거리 음식 문화에 관한 연구에 요리 인류학을 통합했어요.', example_en_3 = 'Culinary anthropology examines how food practices reflect social structures.', example_ko_3 = '요리 인류학은 음식 관행이 어떻게 사회 구조를 반영하는지 조사해요.', example_en_4 = 'He used culinary anthropology to explain why certain foods are taboo in specific cultures.', example_ko_4 = '그는 요리 인류학을 사용하여 왜 특정 문화에서 특정 음식이 금기시되는지 설명했어요.', example_en_5 = 'Culinary anthropology reveals the deep connection between identity and what we eat.', example_ko_5 = '요리 인류학은 정체성과 우리가 먹는 것 사이의 깊은 연결을 드러내요.' WHERE id = 'w_cooking_C2_29';

UPDATE words SET example_en_2 = 'UNESCO has recognised several gastronomic heritages on its intangible cultural list.', example_ko_2 = '유네스코는 무형 문화 목록에 여러 미식 유산을 인정했어요.', example_en_3 = 'Kimchi''s status as a gastronomic heritage is celebrated in Korea every November.', example_ko_3 = '김치의 미식 유산 지위는 매년 11월 한국에서 기념돼요.', example_en_4 = 'Gastronomic heritage preservation helps communities maintain cultural continuity.', example_ko_4 = '미식 유산 보존은 공동체가 문화적 연속성을 유지하는 데 도움이 돼요.', example_en_5 = 'She founded a foundation dedicated to documenting gastronomic heritage in West Africa.', example_ko_5 = '그녀는 서아프리카의 미식 유산을 기록하는 데 전념하는 재단을 설립했어요.' WHERE id = 'w_cooking_C2_30';

UPDATE words SET example_en_2 = 'A major study used nutritional epidemiology to link processed food to heart disease.', example_ko_2 = '주요 연구는 영양 역학을 사용하여 가공 식품을 심장 질환과 연결했어요.', example_en_3 = 'She published work in nutritional epidemiology on the Mediterranean diet.', example_ko_3 = '그녀는 지중해식 식단에 관한 영양 역학 논문을 발표했어요.', example_en_4 = 'Nutritional epidemiology relies on large population studies and dietary surveys.', example_ko_4 = '영양 역학은 대규모 인구 연구와 식이 조사에 의존해요.', example_en_5 = 'Nutritional epidemiology has shaped public health guidelines on fat and sugar intake.', example_ko_5 = '영양 역학은 지방 및 설탕 섭취에 관한 공중 보건 지침을 형성해 왔어요.' WHERE id = 'w_cooking_C2_31';

UPDATE words SET example_en_2 = 'The Mediterranean dietary pattern is associated with longevity and reduced disease risk.', example_ko_2 = '지중해식 식이 패턴은 장수와 감소된 질병 위험과 관련이 있어요.', example_en_3 = 'She tracked participants'' dietary patterns over ten years for her research.', example_ko_3 = '그녀는 연구를 위해 10년 동안 참가자들의 식이 패턴을 추적했어요.', example_en_4 = 'Shifting to a plant-based dietary pattern can significantly reduce carbon emissions.', example_ko_4 = '식물성 식이 패턴으로 전환하면 탄소 배출량을 크게 줄일 수 있어요.', example_en_5 = 'Dietary pattern research looks at whole diets rather than individual nutrients.', example_ko_5 = '식이 패턴 연구는 개별 영양소보다 전체 식단을 살펴봐요.' WHERE id = 'w_cooking_C2_32';

UPDATE words SET example_en_2 = 'Sustainable food systems require collaboration across agriculture, policy, and industry.', example_ko_2 = '지속 가능한 식품 시스템은 농업, 정책, 산업 전반에 걸친 협력이 필요해요.', example_en_3 = 'She researched how food systems in low-income countries can be made more resilient.', example_ko_3 = '그녀는 저소득 국가의 식품 시스템을 어떻게 더 탄력적으로 만들 수 있는지 연구했어요.', example_en_4 = 'Urban food systems face unique challenges around supply, access, and waste.', example_ko_4 = '도시 식품 시스템은 공급, 접근성, 폐기물에 관한 고유한 도전에 직면해 있어요.', example_en_5 = 'Food systems thinking considers the entire journey from farm to fork to waste.', example_ko_5 = '식품 시스템 사고는 농장에서 식탁을, 그리고 폐기물까지의 전체 여정을 고려해요.' WHERE id = 'w_cooking_C2_33';

UPDATE words SET example_en_2 = 'Protecting agrobiodiversity ensures food security for future generations.', example_ko_2 = '농업 생물 다양성 보호는 미래 세대를 위한 식량 안보를 보장해요.', example_en_3 = 'She works with farmers to preserve rare varieties and maintain agrobiodiversity.', example_ko_3 = '그녀는 희귀 품종을 보존하고 농업 생물 다양성을 유지하기 위해 농부들과 협력해요.', example_en_4 = 'The loss of agrobiodiversity makes crops more vulnerable to pests and disease.', example_ko_4 = '농업 생물 다양성의 손실은 작물을 해충과 질병에 더 취약하게 만들어요.', example_en_5 = 'He studied agrobiodiversity in the Andes, where thousands of potato varieties exist.', example_ko_5 = '그는 수천 가지의 감자 품종이 존재하는 안데스 지역의 농업 생물 다양성을 연구했어요.' WHERE id = 'w_cooking_C2_34';

UPDATE words SET example_en_2 = 'Culinary semiotics examines how food acts as a language of social meaning.', example_ko_2 = '요리 기호학은 음식이 어떻게 사회적 의미의 언어로 작용하는지 조사해요.', example_en_3 = 'She applied culinary semiotics to analyse the symbolic role of food in film.', example_ko_3 = '그녀는 영화에서 음식의 상징적 역할을 분석하기 위해 요리 기호학을 적용했어요.', example_en_4 = 'Culinary semiotics reveals how dishes communicate identity, power, and belonging.', example_ko_4 = '요리 기호학은 요리가 어떻게 정체성, 권력, 소속감을 전달하는지 드러내요.', example_en_5 = 'From a culinary semiotics perspective, a wedding cake carries rich symbolic meaning.', example_ko_5 = '요리 기호학적 관점에서 웨딩 케이크는 풍부한 상징적 의미를 담고 있어요.' WHERE id = 'w_cooking_C2_35';
